// 📜 Ranius Buddy's Family Daily Bread Scripture Vault (Month 1 - Family & Heritage Focus)
const BIBLE_VERSES_VAULT = [
    { text: "But as for me and my house, we will serve the Lord.", tamil: "நானோ என் வீட்டாருமோவென்றால், கர்த்தரையே சேவிப்போம்.", ref: "யோசுவா / Joshua 24:15" },
    { text: "Believe in the Lord Jesus, and you will be saved, you and your household.", tamil: "கர்த்தராகிய இயேசு கிறிஸ்துவை விசுவாசி, அப்பொழுது நீயும் உன் வீட்டாரும் இரட்சிக்கப்படுவீர்கள்.", ref: "அப்போஸ்தலர் / Acts 16:31" },
    { text: "The Lord bless you and keep you; the Lord make his face shine on you and be gracious to you.", tamil: "கர்த்தர் உன்னை ஆசீர்வதித்து, உன்னைக் காக்கக்கடவர்; கர்த்தர் தம்முடைய முகத்தை உன்மேல் பிரகாசிப்பித்து, உன்மேல் கிருபையாயிருக்கக்கடவர்.", ref: "எண்ணாகமம் / Numbers 6:24-25" },
    { text: "I can do all things through Christ who strengthens me.", tamil: "என்னைப் பெலப்படுத்துகிற கிறிஸ்துவினாலே எல்லாவற்றையும் செய்ய எனக்குப் பெலனுண்டு.", ref: "பிலிப்பியர் / Philippians 4:13" },
    { text: "For I know the plans I have for you, declares the Lord, plans for welfare and not for evil, to give you a future and a hope.", tamil: "நீங்கள் எதிர்பாரத்திருக்கும் முடிவை உங்களுக்குக் கொடுக்கும்படிக்கு, நான் உங்களைக்குறித்து நினைத்திருக்கிற நினைவுகளை அறிவேன் என்று கர்த்தர் சொல்லுகிறார்; அவைகள் தீமைக்கல்ல, சமாதானத்துக்கேதுவான நினைவுகள்.", ref: "எரேமியா / Jeremiah 29:11" },
    { text: "Commit your way to the Lord; trust in him, and he will act.", tamil: "உன் வழியைக் கர்த்தருக்கு ஒப்புவித்து, அவர்மேல் நம்பிக்கையாயிரு; அவரே காரியத்தை வாய்க்கப்பண்ணுவார்.", ref: "சங்கீதம் / Psalm 37:5" },
    { text: "The Lord is my shepherd; I shall not want.", tamil: "கர்த்தர் என் மேய்ப்பராயிருக்கிறார்; நான் தாழ்ச்சியடையேன்.", ref: "சங்கீதம் / Psalm 23:1" },
    { text: "As for God, his way is perfect: The Lord’s word is flawless; he shields all who take refuge in him.", tamil: "தேவனுடைய வழி உத்தமமானது; கர்த்தருடைய வசனம் புடமிடப்பட்டது; தம்மை நம்புகிற அனைவருக்கும் அவர் கேடகமாயிருக்கிறார்.", ref: "சங்கீதம் / Psalm 18:30" },
    { text: "But seek first the kingdom of God and his righteousness, and all these things will be added to you.", tamil: "முதலாவது தேவனுடைய ராஜ்யத்தையும் அவருடைய நீதியையும் தேடுங்கள், அப்பொழுது இவைகளெல்லாம் உங்களுக்குக் கூடக் கொடுக்கப்படும்.", ref: "மத்தேயு / Matthew 6:33" },
    { text: "And absolute peace from God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus.", tamil: "எல்லா புத்திக்கும் மேலான தேவ சமாதானம் உங்கள் இருதயங்களையும் உங்கள் சிந்தைகளையும் கிறிஸ்து இயேசுவுக்குள்ளாகக் காத்துக்கொள்ளும்.", ref: "பிலிப்பியர் / Philippians 4:7" },
    { text: "Behold, children are a heritage from the Lord, the fruit of the womb a reward.", tamil: "இதோ, பிள்ளைகள் கர்த்தரால் வரும் சுதந்தரம், கர்ப்பத்தின் கனி அவரால் கிடைக்கும் பலன்.", ref: "சங்கீதம் / Psalm 127:3" },
    { text: "A good man leaves an inheritance to his children's children.", tamil: "நல்லவன் தன் பிள்ளைகளின் பிள்ளைகளுக்குச் சுதந்தரம் வைத்துப்போகிறான்.", ref: "நீதிமொழிகள் / Proverbs 13:22" },
    { text: "Children's children are a crown to the aged, and parents are the pride of their children.", tamil: "பிள்ளைகளின் பிள்ளைகள் முதியோருக்குக் கிரீடம்; பிள்ளைகளின் மேன்மை அவர்கள் பிதாக்களே.", ref: "நீதிமொழிகள் / Proverbs 17:6" },
    { text: "Gray hair is a crown of splendor; it is attained in the way of righteousness.", tamil: "நரைமயிர் மகிமையான கிரீடம், அது நீதியின் வழியிலே காணப்படும்.", ref: "நீதிமொழிகள் / Proverbs 16:31" },
    { text: "Even to your old age and gray hairs I am he, I am he who will sustain you.", tamil: "உங்கள் முதிர்வயதுவரைக்கும் நான் அப்படிச் செய்வேன்; நரைவயதுமட்டும் நான் உங்களைத் தாங்குவேன்.", ref: "ஏசாயா / Isaiah 46:4" },
    { text: "I have no greater joy than to hear that my children are walking in the truth.", tamil: "என் பிள்ளைகள் சத்தியத்திலே நடக்கிறார்கள் என்று நான் கேள்விப்படுகிற சந்தோஷத்திலும் அதிக சந்தோஷம் எனக்கு இல்லை.", ref: "யோவான் 3 / 3 John 1:4" },
    { text: "Train up a child in the way he should go; even when he is old he will not depart from it.", tamil: "பிள்ளையை நடக்கும் வழியிலே நடத்து; அவன் முதிர்வயதிலும் அதை விடாதிருப்பான்.", ref: "நீதிமொழிகள் / Proverbs 22:6" },
    { text: "Honor your father and your mother, that your days may be long in the land that the Lord your God is giving you.", tamil: "உன் தேவனாகிய கர்த்தர் உனக்குக் கொடுக்கிற தேசத்தில் உன் நாட்கள் நீடித்திருப்பதற்கு, உன் தகப்பனையும் உன் தாயையும் கனம்பண்ணுவாயாக.", ref: "யாத்திராகமம் / Exodus 20:12" },
    { text: "How good and pleasant it is when God’s people live together in unity!", tamil: "இதோ, சகோதரர் ஒருமித்து வாசம்பண்ணுகிறது எத்தனை நன்மையும் எத்தனை இன்பமுமானது!", ref: "சங்கீதம் / Psalm 133:1" },
    { text: "Let all that you do be done in love.", tamil: "நீங்கள் செய்கிறதெல்லாம் அன்போடே செய்யப்படக்கடவது.", ref: "கொரிந்தியர் 1 / 1 Corinthians 16:14" },
    { text: "Be kind to one another, tenderhearted, forgiving one another, as God in Christ forgave you.", tamil: "ஒருவருக்கொருவர் தயவாயும் மன உருக்கமாயுமிருந்து, கிறிஸ்துவுக்குள் தேவன் உங்களுக்கு மன்னித்ததுபோல, நீங்களும் ஒருவருக்கொருவர் மன்னியுங்கள்.", ref: "எபேசியர் / Ephesians 4:32" },
    { text: "Above all, keep loving one another earnestly, since love covers a multitude of sins.", tamil: "எல்லாவற்றிற்கும் மேலாக ஒருவரிலொருவர் ஊக்கமான அன்புள்ளவர்களாயிருங்கள்; அன்பு திரளான பாவங்களை மூடும்.", ref: "பேதுரு 1 / 1 Peter 4:8" },
    { text: "The steadfast love of the Lord never ceases; his mercies never come to an end.", tamil: "கர்த்தருடைய கிருபைகளே, நாம் நிர்மூலமாகாதிருக்கிறது; அவருடைய இரக்கங்களுக்கு முடிவில்லை.", ref: "புலம்பல் / Lamentations 3:22" },
    { text: "They are new every morning; great is your faithfulness.", tamil: "அவைகள் காலைதோறும் புதியவைகள்; உமது உண்மை பெரிதாயிருக்கிறது.", ref: "புலம்பல் / Lamentations 3:23" },
    { text: "Trust in the Lord with all your heart, and do not lean on your own understanding.", tamil: "உன் சுயபுத்தியின்மேல் சாயாமல், உன் முழு இருதயத்தோடும் கர்த்தரில் நம்பிக்கையாயிருந்து,", ref: "நீதிமொழிகள் / Proverbs 3:5" },
    { text: "In all your ways acknowledge him, and he will make straight your paths.", tamil: "உன் வழிகளிலெல்லாம் அவரை நினைத்துக்கொள்; அப்பொழுது அவர் உன் பாதைகளைச் செவ்வைப்படுத்துவார்.", ref: "நீதிமொழிகள் / Proverbs 3:6" },
    { text: "Fear not, for I am with you; be not dismayed, for I am your God.", tamil: "நீ பயப்படாதே, நான் உன்னுடனே இருக்கிறேன்; திகையாதே, நான் உன் தேவன்.", ref: "ஏசாயா / Isaiah 41:10" },
    { text: "I will strengthen you, I will help you, I will uphold you with my righteous right hand.", tamil: "நான் உன்னைப் பலப்படுத்தி உனக்குச் சகாயம்பண்ணுவேன்; என் நீதியின் வலதுகரத்தினால் உன்னைத் தாங்குவேன்.", ref: "ஏசாயா / Isaiah 41:10" },
    { text: "Your word is a lamp to my feet and a light to my path.", tamil: "உம்முடைய வசனம் என் கால்களுக்குத் தீபமும், என் பாதைக்கு வெளிச்சமுமாயிருக்கிறது.", ref: "சங்கீதம் / Psalm 119:105" },
    { text: "And we know that for those who love God all things work together for good.", tamil: "அன்றியும், அவருடைய தீர்மானத்தின்படி அழைக்கப்பட்டவர்களாய் தேவனிடத்தில் அன்புகூருகிறவர்களுக்குச் சகலமும் நன்மைக்கேதுவாக நடக்கிறது என்று அறிந்திருக்கிறோம்.", ref: "ரோமர் / Romans 8:28" },
    { text: "May the God of hope fill you with all joy and peace in believing.", tamil: "பரிசுத்த ஆவியின் பலத்தினாலே உங்களுக்கு நம்பிக்கை பெருகும்படிக்கு, நம்பிக்கையின் தேவன் விசுவாசிக்கிறதினால் உண்டாகும் எல்லாவித சந்தோஷத்தினாலும் சமாதானத்தினாலும் உங்களை நிரப்புவாராக.", ref: "ரோமர் / Romans 15:13" },
        // --- MONTH 2 (Days 32-61) ---
    { text: "He who finds a wife finds a good thing and obtains favor from the Lord.", tamil: "மனைவியைக் கண்டடைகிறவன் நன்மையானதைக் கண்டடைகிறான்; கர்த்தரால் தயவையும் பெறுவான்.", ref: "நீதிமொழிகள் / Proverbs 18:22" },
    { text: "Her children rise up and call her blessed; her husband also, and he praises her.", tamil: "அவள் பிள்ளைகள் எழும்பி, அவளைப் பாக்கியவதி என்கிறார்கள்; அவள் புருஷனும் அவளைப் புகழுகிறான்.", ref: "நீதிமொழிகள் / Proverbs 31:28" },
    { text: "And my God will supply every need of yours according to his riches in glory in Christ Jesus.", tamil: "என் தேவன் தம்முடைய ஐசுவரியத்தின்படி உங்கள் குறைவையெல்லாம் கிறிஸ்து இயேசுவுக்குள் மகிமையாக நிறைவாக்குவார்.", ref: "பிலிப்பியர் / Philippians 4:19" },
    { text: "Rejoice in hope, be patient in tribulation, be constant in prayer.", tamil: "நம்பிக்கையிலே சந்தோஷமாயிருங்கள்; உபத்திரவத்திலே பொறுமையாயிருங்கள்; ஜெபத்திலே உறுதியாய்த்தரித்திருங்கள்.", ref: "ரோமர் / Romans 12:12" },
    { text: "Rejoice always, pray without ceasing, give thanks in all circumstances.", tamil: "எப்பொழுதும் சந்தோஷமாயிருங்கள். இடைவிடாமல் ஜெபம்பண்ணுங்கள். எல்லாவற்றிலேயும் ஸ்தோத்திரஞ்செய்யுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:16-18" },
    { text: "Children, obey your parents in the Lord, for this is right.", tamil: "பிள்ளைகளே, உங்கள் பெற்றோருக்குக் கர்த்தருக்குள் கீழ்ப்படியுங்கள், இது நியாயம்.", ref: "எபேசியர் / Ephesians 6:1" },
    { text: "Fathers, do not provoke your children to anger, but bring them up in the discipline and instruction of the Lord.", tamil: "பிதாக்களே, நீங்களும் உங்கள் பிள்ளைகளுக்குக் கோபமூட்டாமல், கர்த்தருக்கேற்ற சிட்சையிலும் போதனையிலும் அவர்களை வளர்க்கக்கடவீர்கள்.", ref: "எபேசியர் / Ephesians 6:4" },
    { text: "Have I not commanded you? Be strong and courageous. Do not be frightened, and do not be dismayed, for the Lord your God is with you wherever you go.", tamil: "நான் உனக்குக் கட்டளையிடவில்லையா? பலங்கொண்டு திடமனதாயிரு; திகையாதே, கலங்காதே, நீ போகும் இடமெல்லாம் உன் தேவனாகிய கர்த்தர் உன்னோடே இருக்கிறார்.", ref: "யோசுவா / Joshua 1:9" },
    { text: "God is our refuge and strength, a very present help in trouble.", tamil: "தேவன் நமக்கு அடைக்கலமும் பெலனும், ஆபத்துக்காலத்தில் அநுகூலமுமான துணையுமானவர்.", ref: "சங்கீதம் / Psalm 46:1" },
    { text: "I lift up my eyes to the hills. From where does my help come? My help comes from the Lord, who made heaven and earth.", tamil: "எனக்கு ஒத்தாசை வரும் பர்வதங்களுக்கு நேராக என் கண்களை ஏறெடுக்கிறேன். வானத்தையும் பூமியையும் உண்டாக்கின கர்த்தரிடத்திலிருந்து எனக்கு ஒத்தாசை வரும்.", ref: "சங்கீதம் / Psalm 121:1-2" },
    { text: "Oh give thanks to the Lord, for he is good; for his steadfast love endures forever!", tamil: "கர்த்தரைத் துதியுங்கள், அவர் நல்லவர்; அவர் கிருபை என்றுமுள்ளது.", ref: "சங்கீதம் / Psalm 118:1" },
    { text: "But they who wait for the Lord shall renew their strength; they shall mount up with wings like eagles.", tamil: "கர்த்தருக்குக் காத்திருக்கிறவர்களோ புதுப்பெலன் அடைந்து, கழுகுகளைப்போலச் சட்டைகளை அடித்து எழும்புவார்கள்.", ref: "ஏசாயா / Isaiah 40:31" },
    { text: "Come to me, all who labor and are heavy laden, and I will give you rest.", tamil: "வருத்தப்பட்டுப் பாரஞ்சுமக்கிறவர்களே! நீங்கள் எல்லாரும் என்னிடத்தில் வாருங்கள்; நான் உங்களுக்கு இளைப்பாறுதல் தருவேன்.", ref: "மத்தேயு / Matthew 11:28" },
    { text: "Peace I leave with you; my peace I give to you. Not as the world gives do I give to you.", tamil: "சமாதானத்தை உங்களுக்கு வைத்துப்போகிறேன், என்னுடைய சமாதானத்தையே உங்களுக்குக் கொடுக்கிறேன்; உலகம் கொடுக்கிறபிரகாரம் நான் உங்களுக்குக் கொடுக்கிறதில்லை.", ref: "யோவான் / John 14:27" },
    { text: "The blessing of the Lord makes rich, and he adds no sorrow with it.", tamil: "கர்த்தரின் ஆசீர்வாதமே ஐசுவரியத்தைத் தரும்; அதனோடே அவர் வேதனையைக் கூட்டார்.", ref: "நீதிமொழிகள் / Proverbs 10:22" },
    { text: "Oh, taste and see that the Lord is good! Blessed is the man who takes refuge in him!", tamil: "கர்த்தர் நல்லவர் என்பதை ருசித்துப்பாருங்கள்; அவர்மேல் நம்பிக்கையாயிருக்கிற மனுஷன் பாக்கியவான்.", ref: "சங்கீதம் / Psalm 34:8" },
    { text: "Bless the Lord, O my soul, and all that is within me, bless his holy name!", tamil: "என் ஆத்துமாவே, கர்த்தரை ஸ்தோத்திரி; என் முழு உள்ளமே, அவருடைய பரிசுத்த நாமத்தை ஸ்தோத்திரி.", ref: "சங்கீதம் / Psalm 103:1" },
    { text: "We love because he first loved us.", tamil: "அவர் முந்தி நம்மிடத்தில் அன்புகூர்ந்தபடியால் நாமும் அவரிடத்தில் அன்புகூருகிறோம்.", ref: "யோவான் 1 / 1 John 4:19" },
    { text: "Every good gift and every perfect gift is from above, coming down from the Father of lights.", tamil: "நன்மையான எந்த ஈவும் பூரணமான எந்த வரமும் மேலிருந்து உண்டாகி, ஜோதிகளின் பிதாவினிடத்திலிருந்து இறங்கிவருகிறது.", ref: "யாக்கோபு / James 1:17" },
    { text: "I will never leave you nor forsake you.", tamil: "நான் உன்னைவிட்டு விலகுவதுமில்லை, உன்னைக் கைவிடுவதுமில்லை.", ref: "எபிரெயர் / Hebrews 13:5" },
    { text: "Do not be conformed to this world, but be transformed by the renewal of your mind.", tamil: "நீங்கள் இந்தப் பிரபஞ்சத்திற்கு ஒத்த வேஷந்தரியாமல், தேவனுடைய நன்மையும் பிரியமும் பரிபூரணமுமான சித்தம் இன்னதென்று பகுத்தறியத்தக்கதாக, உங்கள் மனம் புதிதாகிறதினாலே மறுரூபமாகுங்கள்.", ref: "ரோமர் / Romans 12:2" },
    { text: "Keep your heart with all vigilance, for from it flow the springs of life.", tamil: "எல்லாக் காவலோடும் உன் இருதயத்தைக் காத்துக்கொள், அதினிடத்தினின்று ஜீவஊற்று புறப்படும்.", ref: "நீதிமொழிகள் / Proverbs 4:23" },
    { text: "Blessed is the man who walks not in the counsel of the wicked, nor stands in the way of sinners.", tamil: "துன்மார்க்கருடைய ஆலோசனையில் நடவாமலும், பாவிகளுடைய வழியில் நில்லாமலும், பரியாசக்காரர் உட்காரும் இடத்தில் உட்காராமலும்,", ref: "சங்கீதம் / Psalm 1:1" },
    { text: "Do nothing from selfish ambition or conceit, but in humility count others more significant than yourselves.", tamil: "ஒன்றையும் வாதினாலாவது வீண்பெருமையினாலாவது செய்யாமல், மனத்தாழ்மையினாலே ஒருவரையொருவர் தங்களிலும் மேன்மையானவர்களாக எண்ணக்கடவீர்கள்.", ref: "பிலிப்பியர் / Philippians 2:3" },
    { text: "But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness.", tamil: "ஆவியின் கனியோ, அன்பு, சந்தோஷம், சமாதானம், நீடியபொறுமை, தயவு, நற்குணம், விசுவாசம்,", ref: "கலாத்தியர் / Galatians 5:22" },
    { text: "In the same way, let your light shine before others, so that they may see your good works and give glory to your Father who is in heaven.", tamil: "இவ்விதமாய், மனுஷர் உங்கள் நற்கிரியைகளைக் கண்டு, பரலோகத்திலிருக்கிற உங்கள் பிதாவை மகிமைப்படுத்தும்படி, உங்கள் வெளிச்சம் அவர்கள் முன்பாகப் பிரகாசிக்கக்கடவது.", ref: "மத்தேயு / Matthew 5:16" },
    { text: "Let the words of my mouth and the meditation of my heart be acceptable in your sight, O Lord, my rock and my redeemer.", tamil: "என் கன்மலையும் என் மீட்பருமாகிய கர்த்தாவே, என் வாயின் வார்த்தைகளும், என் இருதயத்தின் தியானமும், உமது சமூகத்தில் பிரீதியாயிருப்பதாக.", ref: "சங்கீதம் / Psalm 19:14" },
    { text: "And do not be grieved, for the joy of the Lord is your strength.", tamil: "துக்கப்படவேண்டாம்; கர்த்தருக்குள் மகிழ்ச்சியாயிருப்பதே உங்களுடைய பெலன்.", ref: "நெகேமியா / Nehemiah 8:10" },
    { text: "Call to me and I will answer you, and will tell you great and hidden things that you have not known.", tamil: "என்னை நோக்கிக் கூப்பிடு, அப்பொழுது நான் உனக்கு உத்தரவு கொடுத்து, நீ அறியாததும் உனக்கு எட்டாததுமான பெரிய காரியங்களை உனக்கு அறிவிப்பேன்.", ref: "எரேமியா / Jeremiah 33:3" },
    { text: "For where two or three are gathered in my name, there am I among them.", tamil: "ஏனெனில், இரண்டுபேராவது மூன்றுபேராவது என் நாமத்தினாலே எங்கே கூடியிருக்கிறார்களோ, அங்கே அவர்கள் நடுவிலே இருக்கிறேன்.", ref: "மத்தேயு / Matthew 18:20" },
        // --- MONTH 3 (Days 62-91) ---
    { text: "By wisdom a house is built, and by understanding it is established; by knowledge the rooms are filled with all precious and pleasant riches.", tamil: "ஞானத்தினாலே வீடு கட்டப்பட்டு, புத்தியினாலே நிலைநிறுத்தப்படும். அறிவினாலே அறைகளில் அருமையும் இனிமையுமான சகலவிதப் பொருள்களும் நிரம்பும்.", ref: "நீதிமொழிகள் / Proverbs 24:3-4" },
    { text: "For the Lord is good; his steadfast love endures forever, and his faithfulness to all generations.", tamil: "கர்த்தர் நல்லவர், அவருடைய கிருபை என்றென்றைக்குமுள்ளது, அவருடைய உண்மை தலைமுறை தலைமுறையாகும்.", ref: "சங்கீதம் / Psalm 100:5" },
    { text: "All your children shall be taught by the Lord, and great shall be the peace of your children.", tamil: "உன் பிள்ளைகளெல்லாரும் கர்த்தரால் போதிக்கப்பட்டிருப்பார்கள்; உன் பிள்ளைகளுடைய சமாதானம் பெரிதாயிருக்கும்.", ref: "ஏசாயா / Isaiah 54:13" },
    { text: "Love is patient and kind; love does not envy or boast; it is not arrogant or rude.", tamil: "அன்பு நீடிய சாந்தமும் தயவுமுள்ளது; அன்புக்குப் பொறாமையில்லை; அன்பு தன்னைப் புகழாது, இறுமாப்பாயிராது.", ref: "கொரிந்தியர் 1 / 1 Corinthians 13:4" },
    { text: "Love bears all things, believes all things, hopes all things, endures all things.", tamil: "சகலத்தையும் தாங்கும், சகலத்தையும் விசுவாசிக்கும், சகலத்தையும் நம்பும், சகலத்தையும் சகிக்கும்.", ref: "கொரிந்தியர் 1 / 1 Corinthians 13:7" },
    { text: "Blessed is everyone who fears the Lord, who walks in his ways!", tamil: "கர்த்தருக்குப் பயந்து, அவர் வழிகளில் நடக்கிறவன் எவனோ அவன் பாக்கியவான்.", ref: "சங்கீதம் / Psalm 128:1" },
    { text: "You shall eat the fruit of the labor of your hands; you shall be blessed, and it shall be well with you.", tamil: "உன் கைகளின் பிரயாசத்தை நீ சாப்பிடுவாய்; உனக்குப் பாக்கியமும் நன்மையும் உண்டாயிருக்கும்.", ref: "சங்கீதம் / Psalm 128:2" },
    { text: "Your wife will be like a fruitful vine within your house; your children will be like olive shoots around your table.", tamil: "உன் மனைவி உன் வீட்டோரங்களில் கனிதரும் திராட்சக்கொடியைப்போல் இருப்பாள்; உன் பிள்ளைகள் உன் பந்தியைச் சுற்றிலும் ஒலிவமரக் கன்றுகளைப்போல் இருப்பார்கள்.", ref: "சங்கீதம் / Psalm 128:3" },
    { text: "Beloved, I pray that all may go well with you and that you may be in good health, as it goes well with your soul.", tamil: "பிரியமானவனே, உன் ஆத்துமா வாழ்கிறதுபோல நீ எல்லாவற்றிலும் வாழ்ந்து சுகமாயிருக்கும்படி வேண்டுகிறேன்.", ref: "யோவான் 3 / 3 John 1:2" },
    { text: "The Lord lift up his countenance upon you and give you peace.", tamil: "கர்த்தர் தம்முடைய முகத்தை உன்மேல் பிரசன்னமாக்கி, உனக்குச் சமாதானம் கட்டளையிடக்கடவர்.", ref: "எண்ணாகமம் / Numbers 6:26" },
    { text: "The angel of the Lord encamps around those who fear him, and delivers them.", tamil: "கர்த்தருடைய தூதன் அவருக்குப் பயந்தவர்களைச் சுற்றிலும் பாளயமிறங்கி அவர்களை விடுவிக்கிறார்.", ref: "சங்கீதம் / Psalm 34:7" },
    { text: "Let not steadfast love and faithfulness forsake you; bind them around your neck.", tamil: "கிருபையும் சத்தியமும் உன்னைவிட்டு விலகாதிருப்பதாக; நீ அவைகளை உன் கழுத்தில் பூண்டு, உன் இருதயமாகிய பலகையில் எழுதிக்கொள்.", ref: "நீதிமொழிகள் / Proverbs 3:3" },
    { text: "But Jesus said, 'Let the little children come to me and do not hinder them, for to such belongs the kingdom of heaven.'", tamil: "இயேசு சிறுபிள்ளைகளைத் தம்மிடத்தில் வரவிடுங்கள்; அவர்களைத் தடைபண்ணாதிருங்கள்; பரலோகராஜ்யம் அப்படிப்பட்டவர்களுடையது என்றார்.", ref: "மத்தேயு / Matthew 19:14" },
    { text: "Do not be anxious about anything, but in everything by prayer and supplication with thanksgiving let your requests be made known to God.", tamil: "நீங்கள் ஒன்றுக்குங்கவலைப்படாமல், எல்லாவற்றையுங்குறித்து உங்கள் விண்ணப்பங்களை ஸ்தோத்திரத்தோடுகூடிய ஜெபத்தினாலும் வேண்டுதலினாலும் தேவனுக்குத் தெரியப்படுத்துங்கள்.", ref: "பிலிப்பியர் / Philippians 4:6" },
    { text: "And above all these put on love, which binds everything together in perfect harmony.", tamil: "இவைகள் எல்லாவற்றின்மேலும், பூரண சற்குணத்தின் கட்டாகிய அன்பைத் தரித்துக்கொள்ளுங்கள்.", ref: "கொலோசெயர் / Colossians 3:14" },
    { text: "And let the peace of Christ rule in your hearts, to which indeed you were called in one body. And be thankful.", tamil: "தேவ சமாதானம் உங்கள் இருதயங்களில் ஆளக்கடவது, இதற்கென்றே நீங்கள் ஒரே சரீரமாக அழைக்கப்பட்டீர்கள்; நன்றியறிதலுள்ளவர்களாயுமிருங்கள்.", ref: "கொலோசெயர் / Colossians 3:15" },
    { text: "Casting all your anxieties on him, because he cares for you.", tamil: "அவர் உங்களை விசாரிக்கிறவரானபடியால், உங்கள் கவலைகளையெல்லாம் அவர்மேல் வைத்துவிடுங்கள்.", ref: "பேதுரு 1 / 1 Peter 5:7" },
    { text: "Now faith is the assurance of things hoped for, the conviction of things not seen.", tamil: "விசுவாசமானது நம்பப்படுகிறவைகளின் உறுதியும், காணப்படாதவைகளின் நிச்சயமுமாயிருக்கிறது.", ref: "எபிரெயர் / Hebrews 11:1" },
    { text: "The Lord is my light and my salvation; whom shall I fear?", tamil: "கர்த்தர் என் வெளிச்சமும் என் இரட்சிப்புமானவர், யாருக்குப் பயப்படுவேன்?", ref: "சங்கீதம் / Psalm 27:1" },
    { text: "I have stored up your word in my heart, that I might not sin against you.", tamil: "நான் உமக்கு விரோதமாய்ப் பாவஞ்செய்யாதபடிக்கு, உமது வாக்கை என் இருதயத்தில் வைத்து வைத்தேன்.", ref: "சங்கீதம் / Psalm 119:11" },
    { text: "Commit your work to the Lord, and your plans will be established.", tamil: "உன் செய்கைகளைக் கர்த்தருக்கு ஒப்புவி; அப்பொழுது உன் யோசனைகள் நிலைபெறும்.", ref: "நீதிமொழிகள் / Proverbs 16:3" },
    { text: "You keep him in perfect peace whose mind is stayed on you, because he trusts in you.", tamil: "உம்மை உறுதியாய்ப் பற்றிக்கொண்ட மனதையுடையவன் உம்மையே நம்பியிருக்கிறபடியால், நீர் அவனைப் பூரண சமாதானத்துடன் காத்துக்கொள்வீர்.", ref: "ஏசாயா / Isaiah 26:3" },
    { text: "Love one another with brotherly affection. Outdo one another in showing honor.", tamil: "சகோதர சிநேகத்திலே ஒருவர்மேலொருவர் பட்சமாயிருங்கள்; கனம்பண்ணுகிறதிலே ஒருவருக்கொருவர் முந்திக்கொள்ளுங்கள்.", ref: "ரோமர் / Romans 12:10" },
    { text: "And let us not grow weary of doing good, for in due season we will reap, if we do not give up.", tamil: "நன்மைசெய்கிறதில் சோர்ந்துபோகாமல் இருப்போமாக; நாம் தளர்ந்துபோகாதிருந்தால் ஏற்றகாலத்தில் அறுப்போம்.", ref: "கலாத்தியர் / Galatians 6:9" },
    { text: "For by grace you have been saved through faith. And this is not your own doing; it is the gift of God.", tamil: "கிருபையினாலே விசுவாசத்தைக்கொண்டு இரட்சிக்கப்பட்டீர்கள்; இது உங்களால் உண்டானதல்ல, இது தேவனுடைய ஈவு.", ref: "எபேசியர் / Ephesians 2:8" },
    { text: "Little children, let us not love in word or talk but in deed and in truth.", tamil: "என் சிறுபிள்ளைகளே, வசனத்தினாலும் நாவினாலுமல்ல, கிரியையினாலும் உண்மையினாலும் அன்புகூரக்கடவோம்.", ref: "யோவான் 1 / 1 John 3:18" },
    { text: "For he will command his angels concerning you to guard you in all your ways.", tamil: "உன் வழிகளிலெல்லாம் உன்னைக் காக்கும்படி, உனக்காகத் தம்முடைய தூதர்களுக்குக் கட்டளையிடுவார்.", ref: "சங்கீதம் / Psalm 91:11" },
    { text: "The memory of the righteous is a blessing, but the name of the wicked will rot.", tamil: "நீதிமானுடைய பேர் விளங்கும்; துன்மார்க்கனுடைய பேரோ அழிந்துபோகும்.", ref: "நீதிமொழிகள் / Proverbs 10:7" },
    { text: "With my whole heart I seek you; let me not wander from your commandments!", tamil: "என் முழு இருதயத்தோடும் உம்மைத் தேடுகிறேன்; உமது கற்பனைகளைவிட்டு என்னை வழிதப்பவிடாதேயும்.", ref: "சங்கீதம் / Psalm 119:10" },
    { text: "Now therefore fear the Lord and serve him in sincerity and in faithfulness.", tamil: "ஆகையால் நீங்கள் கர்த்தருக்குப் பயந்து, அவரை உத்தமமும் உண்மையுமாய்ச் சேவித்து...", ref: "யோசுவா / Joshua 24:14" },
        // --- MONTH 4 (Days 92-121) ---
    { text: "My son, do not forget my teaching, but let your heart keep my commandments, for length of days and years of life and peace they will add to you.", tamil: "என் மகனே, என் போதகத்தை மறவாதே; உன் இருதயம் என் கட்டளைகளைக் காக்கக்கடவது. அவைகள் உனக்கு நீடித்த நாட்களையும், ஜீவிய காலத்தையும், சமாதானத்தையும் பெருகப்பண்ணும்.", ref: "நீதிமொழிகள் / Proverbs 3:1-2" },
    { text: "This Book of the Law shall not depart from your mouth, but you shall meditate on it day and night...", tamil: "இந்த நியாயப்பிரமாண புஸ்தகம் உன் வாயைவிட்டுப் பிரியாதிருப்பதாக; இதில் எழுதியிருக்கிறவைகளின்படியெல்லாம் நீ செய்யக் கவனமாயிருக்கும்படி, இரவும் பகலும் அதைத் தியானித்துக்கொண்டிருப்பாயாக...", ref: "யோசுவா / Joshua 1:8" },
    { text: "But his delight is in the law of the Lord, and on his law he meditates day and night.", tamil: "கர்த்தருடைய வேதத்தில் பிரியமாயிருந்து, இரவும் பகலும் அவருடைய வேதத்தில் தியானமாயிருக்கிற மனுஷன் பாக்கியவான்.", ref: "சங்கீதம் / Psalm 1:2" },
    { text: "Therefore do not be anxious about tomorrow, for tomorrow will be anxious for itself. Sufficient for the day is its own trouble.", tamil: "ஆகையால், நாளைக்காகக் கவலைப்படாதிருங்கள்; நாளையத்தினம் தன்னுடையவைகளுக்காகக் கவலைப்படும். அந்தந்த நாளுக்கு அதினதின் பாடு போதும்.", ref: "மத்தேயு / Matthew 6:34" },
    { text: "Ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you.", tamil: "கேளுங்கள், அப்பொழுது உங்களுக்குக் கொடுக்கப்படும்; தேடுங்கள், அப்பொழுது கண்டடைவீர்கள்; தட்டுங்கள், அப்பொழுது உங்களுக்குத் திறக்கப்படும்.", ref: "மத்தேயு / Matthew 7:7" },
    { text: "Finally, brothers, whatever is true, whatever is honorable, whatever is just, whatever is pure, whatever is lovely, whatever is commendable...", tamil: "கடைசியாக, சகோதரரே, உண்மையுள்ளவைகளெவைகளோ, ஒழுக்கமுள்ளவைகளெவைகளோ, நீதியுள்ளவைகளெவைகளோ, கற்புள்ளவைகளெவைகளோ, அன்புள்ளவைகளெவைகளோ, நற்கீர்த்தியுள்ளவைகளெவைகளோ...", ref: "பிலிப்பியர் / Philippians 4:8" },
    { text: "Whatever you do, work heartily, as for the Lord and not for men.", tamil: "நீங்கள் எதைச் செய்தாலும், அதை மனுஷர்களுக்கென்று செய்யாமல், கர்த்தருக்கென்றே மனப்பூர்வமாய்ச் செய்யுங்கள்.", ref: "கொலோசெயர் / Colossians 3:23" },
    { text: "So, whether you eat or drink, or whatever you do, do all to the glory of God.", tamil: "ஆகையால் நீங்கள் புசித்தாலும், குடித்தாலும், எதைச் செய்தாலும், எல்லாவற்றையும் தேவனுடைய மகிமைக்கென்று செய்யுங்கள்.", ref: "கொரிந்தியர் 1 / 1 Corinthians 10:31" },
    { text: "For God gave us a spirit not of fear but of power and love and self-control.", tamil: "தேவன் நமக்குப் பயமுள்ள ஆவியைக் கொடாமல், பலமும் அன்பும் தெளிந்த புத்தியுமுள்ள ஆவியையே கொடுத்திருக்கிறார்.", ref: "தீமோத்தேயு 2 / 2 Timothy 1:7" },
    { text: "There is no fear in love, but perfect love casts out fear.", tamil: "அன்பில் பயமில்லை; பூரண அன்பு பயத்தைப் புறம்பே தள்ளும்.", ref: "யோவான் 1 / 1 John 4:18" },
    { text: "I will bless the Lord at all times; his praise shall continually be in my mouth.", tamil: "கர்த்தரை நான் எக்காலத்திலும் ஸ்தோத்திரிப்பேன்; அவர் துதி எப்போதும் என் வாயிலிருக்கும்.", ref: "சங்கீதம் / Psalm 34:1" },
    { text: "I sought the Lord, and he answered me and delivered me from all my fears.", tamil: "நான் கர்த்தரைத் தேடினேன், அவர் எனக்குச் செவிகொடுத்து, என்னுடைய எல்லாப் பயத்துக்கும் என்னை நீங்கலாக்கிவிட்டார்.", ref: "சங்கீதம் / Psalm 34:4" },
    { text: "I praise you, for I am fearfully and wonderfully made. Wonderful are your works; my soul knows it very well.", tamil: "நான் பிரமிக்கத்தக்கதும் அதிசயமுமாக உண்டாக்கப்பட்டபடியால், உம்மைத் துதிப்பேன்; உமது கிரியைகள் அதிசயமானவைகள், அது என் ஆத்துமாவுக்கு நன்றாய்த் தெரியும்.", ref: "சங்கீதம் / Psalm 139:14" },
    { text: "The heart of man plans his way, but the Lord establishes his steps.", tamil: "மனுஷனுடைய இருதயம் அவனுடைய வழியை யோசிக்கும்; அவனுடைய நடைகளை நடத்துகிறவரோ கர்த்தர்.", ref: "நீதிமொழிகள் / Proverbs 16:9" },
    { text: "Fear not, for I have redeemed you; I have called you by name, you are mine.", tamil: "பயப்படாதே, உன்னை மீட்டுக்கொண்டேன்; உன்னைப் பேர்சொல்லி அழைத்தேன்; நீ என்னுடையவன்.", ref: "ஏசாயா / Isaiah 43:1" },
    { text: "No weapon that is fashioned against you shall succeed, and you shall refute every tongue that rises against you in judgment.", tamil: "உனக்கு விரோதமாய் உருவாக்கப்படும் எந்த ஆயுதமும் வாய்க்காதேபோம்; உனக்கு விரோதமாய் நியாயத்தில் எழும்பும் எந்த நாவையும் நீ குற்றப்படுத்துவாய்.", ref: "ஏசாயா / Isaiah 54:17" },
    { text: "Blessed is the man who trusts in the Lord, whose trust is the Lord.", tamil: "கர்த்தர்மேல் நம்பிக்கையாயிருந்து, கர்த்தரைத் தன் நம்பிக்கையாகக் கொண்டிருக்கிற மனுஷன் பாக்கியவான்.", ref: "எரேமியா / Jeremiah 17:7" },
    { text: "The Lord your God is in your midst, a mighty one who will save; he will rejoice over you with gladness...", tamil: "உன் தேவனாகிய கர்த்தர் உன் நடுவில் இருக்கிறார்; அவர் வல்லமையுள்ளவர், அவர் இரட்சிப்பார்; அவர் உன்பேரில் சந்தோஷமாய் மகிழ்ந்து...", ref: "செப்பனியா / Zephaniah 3:17" },
    { text: "What then shall we say to these things? If God is for us, who can be against us?", tamil: "இவைகளைக்குறித்து நாம் என்னசொல்லுவோம்? தேவன் நம்முடைய பட்சத்திலிருந்தால் நமக்கு விரோதமாயிருப்பவன் யார்?", ref: "ரோமர் / Romans 8:31" },
    { text: "For we walk by faith, not by sight.", tamil: "நாங்கள் தரிசித்து நடவாமல், விசுவாசித்து நடக்கிறோம்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 5:7" },
    { text: "I have been crucified with Christ. It is no longer I who live, but Christ who lives in me.", tamil: "கிறிஸ்துவுடனேகூடச் சிலுவையிலறையப்பட்டேன்; ஆயினும், பிழைத்திருக்கிறேன்; இனி நான் அல்ல, கிறிஸ்துவே எனக்குள் பிழைத்திருக்கிறார்.", ref: "கலாத்தியர் / Galatians 2:20" },
    { text: "For we are his workmanship, created in Christ Jesus for good works...", tamil: "ஏனெனில், நற்கிரியைகளைச் செய்கிறதற்கு நாம் கிறிஸ்து இயேசுவுக்குள் சிருஷ்டிக்கப்பட்டு, தேவனுடைய செய்கையாயிருக்கிறோம்.", ref: "எபேசியர் / Ephesians 2:10" },
    { text: "But be doers of the word, and not hearers only, deceiving yourselves.", tamil: "அல்லாமலும், நீங்கள் உங்களை வஞ்சியாதபடிக்குத் திருவசனத்தைக் கேட்கிறவர்களாய் மாத்திரமல்ல, அதின்படி செய்கிறவர்களாயும் இருங்கள்.", ref: "யாக்கோபு / James 1:22" },
    { text: "But you are a chosen race, a royal priesthood, a holy nation, a people for his own possession...", tamil: "நீங்களோ, உங்களை அந்தகாரத்தினின்று தம்முடைய ஆச்சரியமான ஒளியினிடத்திற்கு வரவழைத்தவருடைய புண்ணியங்களை அறிவிக்கும்படிக்குத் தெரிந்துகொள்ளப்பட்ட சந்ததியாயும், ராஜரீகமான ஆசாரியக்கூட்டமாயும், பரிசுத்த ஜாதியாயும், அவருக்குச் சொந்தமான ஜனமாயும் இருக்கிறீர்கள்.", ref: "பேதுரு 1 / 1 Peter 2:9" },
    { text: "Bless the Lord, O my soul, and forget not all his benefits.", tamil: "என் ஆத்துமாவே, கர்த்தரை ஸ்தோத்திரி; அவர் செய்த சகல உபகாரங்களையும் மறவாதே.", ref: "சங்கீதம் / Psalm 103:2" },
    { text: "You are my hiding place and my shield; I hope in your word.", tamil: "என் மறைவிடமும் என் கேடகமும் நீரே; உம்முடைய வசனத்துக்குக் காத்திருக்கிறேன்.", ref: "சங்கீதம் / Psalm 119:114" },
    { text: "The name of the Lord is a strong tower; the righteous man runs into it and is safe.", tamil: "கர்த்தரின் நாமம் பலத்த துருகம்; நீதிமான் அதற்குள் ஓடிச் சுகமாயிருப்பான்.", ref: "நீதிமொழிகள் / Proverbs 18:10" },
    { text: "Let not your hearts be troubled. Believe in God; believe also in me.", tamil: "உங்கள் இருதயம் கலங்காதிருப்பதாக; தேவனிடத்தில் விசுவாசமாயிருங்கள், என்னிடத்திலும் விசுவாசமாயிருங்கள்.", ref: "யோவான் / John 14:1" },
    { text: "Jesus said to him, 'I am the way, and the truth, and the life. No one comes to the Father except through me.'", tamil: "அதற்கு இயேசு: நானே வழியும் சத்தியமும் ஜீவனுமாயிருக்கிறேன்; என்னாலேயல்லாமல் ஒருவனும் பிதாவினிடத்தில் வரான்.", ref: "யோவான் / John 14:6" },
    { text: "For everyone who calls on the name of the Lord will be saved.", tamil: "ஆதலால் கர்த்தருடைய நாமத்தைத் தொழுதுகொள்ளுகிற எவனும் இரட்சிக்கப்படுவான்.", ref: "ரோமர் / Romans 10:13" },
        // --- MONTH 5 (Days 122-151) ---
    { text: "The wisest of women builds her house, but folly with her own hands tears it down.", tamil: "புத்தியுள்ள ஸ்திரீ தன் வீட்டைக் கட்டுகிறாள்; புத்தியில்லாத ஸ்திரீயோ தன் கைகளினால் அதை இடித்துப்போடுகிறாள்.", ref: "நீதிமொழிகள் / Proverbs 14:1" },
    { text: "So they are no longer two but one flesh. What therefore God has joined together, let not man put asunder.", tamil: "இவ்விதமாய் அவர்கள் இருவராயிராமல், ஒரே மாம்சமாயிருக்கிறார்கள்; ஆகையால், தேவன் இணைத்ததை மனுஷன் பிரிக்காதிருக்கக்கடவன் என்றார்.", ref: "மத்தேயு / Matthew 19:6" },
    { text: "Children, obey your parents in everything, for this pleases the Lord.", tamil: "பிள்ளைகளே, உங்களைப் பெற்றவர்களுக்கு எல்லாக் காரியத்திலேயும் கீழ்ப்படியுங்கள்; இது கர்த்தருக்குப் பிரியமானது.", ref: "கொலோசெயர் / Colossians 3:20" },
    { text: "No one has ever seen God; if we love one another, God abides in us and his love is perfected in us.", tamil: "தேவனை ஒருவனும் ஒருக்காலுங் கண்டதில்லை; நாம் ஒருவரிலொருவர் அன்புகூர்ந்தால் தேவன் நமக்குள் நிலைத்திருப்பார்; அவருடைய அன்பும் நமக்குள் பூரணப்படும்.", ref: "யோவான் 1 / 1 John 4:12" },
    { text: "Rejoice with those who rejoice, weep with those who weep.", tamil: "சந்தோஷப்படுகிறவர்களுடனே சந்தோஷப்படுங்கள், அழுகிறவர்களுடனே அழுங்கள்.", ref: "ரோமர் / Romans 12:15" },
    { text: "The righteous who walks in his integrity—blessed are his children after him!", tamil: "நீதிமான் தன் உத்தமத்திலே நடக்கிறான்; அவனுக்குப்பிறகு அவனுடைய பிள்ளைகளும் பாக்கியவான்களாயிருப்பார்கள்.", ref: "நீதிமொழிகள் / Proverbs 20:7" },
    { text: "But the steadfast love of the Lord is from everlasting to everlasting on those who fear him, and his righteousness to children's children.", tamil: "கர்த்தருடைய கிருபையோ அவருக்குப் பயந்தவர்கள்மேலும், அவருடைய நீதி அவர்கள் பிள்ளைகளின் பிள்ளைகள்மேலும், அநாதியாய் என்றென்றைக்கும் உள்ளது.", ref: "சங்கீதம் / Psalm 103:17" },
    { text: "Therefore encourage one another and build one another up, just as you are doing.", tamil: "ஆகையால், நீங்கள் செய்துவருகிறபடியே, ஒருவரையொருவர் தேற்றி, ஒருவருக்கொருவர் பக்திவிருத்தி உண்டாகும்படி செய்யுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:11" },
    { text: "How can a young man keep his way pure? By guarding it according to your word.", tamil: "வாலிபன் தன் வழியை எதினால் சுத்தம்பண்ணுவான்? உமது வசனத்தின்படி தன்னைக் காத்துக்கொள்ளுகிறதினால்தானே.", ref: "சங்கீதம் / Psalm 119:9" },
    { text: "A wise son makes a glad father, but a foolish man despises his mother.", tamil: "ஞானமுள்ள மகன் தகப்பனைச் சந்தோஷப்படுத்துகிறான்; மதியீனனோ தன் தாயை அசட்டைபண்ணுகிறான்.", ref: "நீதிமொழிகள் / Proverbs 15:20" },
    { text: "Blessed are the peacemakers, for they shall be called sons of God.", tamil: "சமாதானம்பண்ணுகிறவர்கள் பாக்கியவான்கள்; அவர்கள் தேவனுடைய புத்திரர் என்னப்படுவார்கள்.", ref: "மத்தேயு / Matthew 5:9" },
    { text: "Husbands, love your wives, as Christ loved the church and gave himself up for her.", tamil: "புருஷர்களே, உங்கள் மனைவிகளில் அன்புகூருங்கள்; அப்படியே கிறிஸ்துவும் சபையில் அன்புகூர்ந்து...", ref: "எபேசியர் / Ephesians 5:25" },
    { text: "Owe no one anything, except to love each other, for the one who loves another has fulfilled the law.", tamil: "ஒருவரிலொருவர் அன்புகூருகிற கடனேயல்லாமல், மற்றொன்றிலும் ஒருவனுக்கும் கடன்படாதிருங்கள்...", ref: "ரோமர் / Romans 13:8" },
    { text: "I will extol you, my God and King, and bless your name forever and ever.", tamil: "என் ராஜாவாகிய தேவனே, உம்மை உயர்த்தி, உம்முடைய நாமத்தை எப்பொழுதும் என்றென்றைக்கும் ஸ்தோத்திரிப்பேன்.", ref: "சங்கீதம் / Psalm 145:1" },
    { text: "He gives power to the faint, and to him who has no might he increases strength.", tamil: "சோர்ந்துபோகிறவனுக்கு அவர் பெலன் கொடுத்து, சத்துவமில்லாதவனுக்குச் சத்துவத்தைப் பெருகப்பண்ணுகிறார்.", ref: "ஏசாயா / Isaiah 40:29" },
    { text: "And I am sure of this, that he who began a good work in you will bring it to completion at the day of Jesus Christ.", tamil: "உங்களில் நற்கிரியையைத் தொடங்கினவர் அதை இயேசுகிறிஸ்துவின் நாள்பரியந்தம் முடிய நடத்திவருவாரென்று நம்பியிருக்கிறேன்.", ref: "பிலிப்பியர் / Philippians 1:6" },
    { text: "And let us consider how to stir up one another to love and good works.", tamil: "அன்புகூரவும் நற்கிரியைகளைச் செய்யவும் நாம் ஏவப்படும்படி ஒருவரையொருவர் கவனித்து;", ref: "எபிரெயர் / Hebrews 10:24" },
    { text: "Finally, all of you, have unity of mind, sympathy, brotherly love, a tender heart, and a humble mind.", tamil: "முடிவாக, நீங்களெல்லாரும் ஏகசிந்தையுள்ளவர்களும், இரக்கமுள்ளவர்களும், சகோதர சிநேகமுள்ளவர்களும், மனஉருக்கமுள்ளவர்களும், இணக்கமுள்ளவர்களுமாயிருந்து;", ref: "பேதுரு 1 / 1 Peter 3:8" },
    { text: "A friend loves at all times, and a brother is born for adversity.", tamil: "சிநேகிதன் எல்லாக் காலத்திலும் சிநேகிப்பான்; இடுக்கணில் உதவவே சகோதரன் பிறந்திருக்கிறான்.", ref: "நீதிமொழிகள் / Proverbs 17:17" },
    { text: "I will instruct you and teach you in the way you should go; I will counsel you with my eye upon you.", tamil: "நான் உனக்குப் போதித்து, நீ நடக்கவேண்டிய வழியை உனக்குக் காட்டுவேன்; உன்மேல் என் கண்ணை வைத்து, உனக்கு ஆலோசனை சொல்லுவேன்.", ref: "சங்கீதம் / Psalm 32:8" },
    { text: "I have set the Lord always before me; because he is at my right hand, I shall not be shaken.", tamil: "கர்த்தரை எப்பொழுதும் எனக்கு முன்பாக வைத்திருக்கிறேன்; அவர் என் வலதுபாரிசத்தில் இருக்கிறபடியால் நான் அசைக்கப்படுவதில்லை.", ref: "சங்கீதம் / Psalm 16:8" },
    { text: "This is my commandment, that you love one another as I have loved you.", tamil: "நான் உங்களில் அன்பாயிருக்கிறதுபோல நீங்களும் ஒருவரிலொருவர் அன்பாயிருக்கவேண்டுமென்பதே என்னுடைய கற்பனையாயிருக்கிறது.", ref: "யோவான் / John 15:12" },
    { text: "The grace of the Lord Jesus Christ and the love of God and the fellowship of the Holy Spirit be with you all.", tamil: "கர்த்தராகிய இயேசுகிறிஸ்துவினுடைய கிருபையும், தேவனுடைய அன்பும், பரிசுத்த ஆவியினுடைய ஐக்கியமும், உங்கள் அனைவரோடுங்கூட இருப்பதாக. ஆமென்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 13:14" },
    { text: "Continue steadfastly in prayer, being watchful in it with thanksgiving.", tamil: "ஜெபத்திலே உறுதியாய்த் தரித்திருங்கள், ஸ்தோத்திரத்துடன் அதிலே விழித்திருங்கள்.", ref: "கொலோசெயர் / Colossians 4:2" },
    { text: "Therefore, confess your sins to one another and pray for one another, that you may be healed.", tamil: "நீங்கள் சொஸ்தமடையும்படிக்கு, உங்கள் குற்றங்களை ஒருவருக்கொருவர் அறிக்கையிட்டு, ஒருவருக்காக ஒருவர் ஜெபம்பண்ணுங்கள்...", ref: "யாக்கோபு / James 5:16" },
    { text: "And this is the confidence that we have toward him, that if we ask anything according to his will he hears us.", tamil: "நாம் எதையாகிலும் அவருடைய சித்தத்தின்படி கேட்டால், அவர் நமக்குச் செவிகொடுக்கிறாரென்பதே அவரைப் பற்றி நாம் கொண்டிருக்கிற தைரியம்.", ref: "யோவான் 1 / 1 John 5:14" },
        // --- MONTH 5 (Days 122-151) ---
    { text: "The wisest of women builds her house, but folly with her own hands tears it down.", tamil: "புத்தியுள்ள ஸ்திரீ தன் வீட்டைக் கட்டுகிறாள்; புத்தியில்லாத ஸ்திரீயோ தன் கைகளினால் அதை இடித்துப்போடுகிறாள்.", ref: "நீதிமொழிகள் / Proverbs 14:1" },
    { text: "So they are no longer two but one flesh. What therefore God has joined together, let not man put asunder.", tamil: "இவ்விதமாய் அவர்கள் இருவராயிராமல், ஒரே மாம்சமாயிருக்கிறார்கள்; ஆகையால், தேவன் இணைத்ததை மனுஷன் பிரிக்காதிருக்கக்கடவன் என்றார்.", ref: "மத்தேயு / Matthew 19:6" },
    { text: "Children, obey your parents in everything, for this pleases the Lord.", tamil: "பிள்ளைகளே, உங்களைப் பெற்றவர்களுக்கு எல்லாக் காரியத்திலேயும் கீழ்ப்படியுங்கள்; இது கர்த்தருக்குப் பிரியமானது.", ref: "கொலோசெயர் / Colossians 3:20" },
    { text: "No one has ever seen God; if we love one another, God abides in us and his love is perfected in us.", tamil: "தேவனை ஒருவனும் ஒருக்காலுங் கண்டதில்லை; நாம் ஒருவரிலொருவர் அன்புகூர்ந்தால் தேவன் நமக்குள் நிலைத்திருப்பார்; அவருடைய அன்பும் நமக்குள் பூரணப்படும்.", ref: "யோவான் 1 / 1 John 4:12" },
    { text: "Rejoice with those who rejoice, weep with those who weep.", tamil: "சந்தோஷப்படுகிறவர்களுடனே சந்தோஷப்படுங்கள், அழுகிறவர்களுடனே அழுங்கள்.", ref: "ரோமர் / Romans 12:15" },
    { text: "The righteous who walks in his integrity—blessed are his children after him!", tamil: "நீதிமான் தன் உத்தமத்திலே நடக்கிறான்; அவனுக்குப்பிறகு அவனுடைய பிள்ளைகளும் பாக்கியவான்களாயிருப்பார்கள்.", ref: "நீதிமொழிகள் / Proverbs 20:7" },
    { text: "But the steadfast love of the Lord is from everlasting to everlasting on those who fear him, and his righteousness to children's children.", tamil: "கர்த்தருடைய கிருபையோ அவருக்குப் பயந்தவர்கள்மேலும், அவருடைய நீதி அவர்கள் பிள்ளைகளின் பிள்ளைகள்மேலும், அநாதியாய் என்றென்றைக்கும் உள்ளது.", ref: "சங்கீதம் / Psalm 103:17" },
    { text: "Therefore encourage one another and build one another up, just as you are doing.", tamil: "ஆகையால், நீங்கள் செய்துவருகிறபடியே, ஒருவரையொருவர் தேற்றி, ஒருவருக்கொருவர் பக்திவிருத்தி உண்டாகும்படி செய்யுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:11" },
    { text: "How can a young man keep his way pure? By guarding it according to your word.", tamil: "வாலிபன் தன் வழியை எதினால் சுத்தம்பண்ணுவான்? உமது வசனத்தின்படி தன்னைக் காத்துக்கொள்ளுகிறதினால்தானே.", ref: "சங்கீதம் / Psalm 119:9" },
    { text: "A wise son makes a glad father, but a foolish man despises his mother.", tamil: "ஞானமுள்ள மகன் தகப்பனைச் சந்தோஷப்படுத்துகிறான்; மதியீனனோ தன் தாயை அசட்டைபண்ணுகிறான்.", ref: "நீதிமொழிகள் / Proverbs 15:20" },
    { text: "Blessed are the peacemakers, for they shall be called sons of God.", tamil: "சமாதானம்பண்ணுகிறவர்கள் பாக்கியவான்கள்; அவர்கள் தேவனுடைய புத்திரர் என்னப்படுவார்கள்.", ref: "மத்தேயு / Matthew 5:9" },
    { text: "Husbands, love your wives, as Christ loved the church and gave himself up for her.", tamil: "புருஷர்களே, உங்கள் மனைவிகளில் அன்புகூருங்கள்; அப்படியே கிறிஸ்துவும் சபையில் அன்புகூர்ந்து...", ref: "எபேசியர் / Ephesians 5:25" },
    { text: "Owe no one anything, except to love each other, for the one who loves another has fulfilled the law.", tamil: "ஒருவரிலொருவர் அன்புகூருகிற கடனேயல்லாமல், மற்றொன்றிலும் ஒருவனுக்கும் கடன்படாதிருங்கள்...", ref: "ரோமர் / Romans 13:8" },
    { text: "I will extol you, my God and King, and bless your name forever and ever.", tamil: "என் ராஜாவாகிய தேவனே, உம்மை உயர்த்தி, உம்முடைய நாமத்தை எப்பொழுதும் என்றென்றைக்கும் ஸ்தோத்திரிப்பேன்.", ref: "சங்கீதம் / Psalm 145:1" },
    { text: "He gives power to the faint, and to him who has no might he increases strength.", tamil: "சோர்ந்துபோகிறவனுக்கு அவர் பெலன் கொடுத்து, சத்துவமில்லாதவனுக்குச் சத்துவத்தைப் பெருகப்பண்ணுகிறார்.", ref: "ஏசாயா / Isaiah 40:29" },
    { text: "And I am sure of this, that he who began a good work in you will bring it to completion at the day of Jesus Christ.", tamil: "உங்களில் நற்கிரியையைத் தொடங்கினவர் அதை இயேசுகிறிஸ்துவின் நாள்பரியந்தம் முடிய நடத்திவருவாரென்று நம்பியிருக்கிறேன்.", ref: "பிலிப்பியர் / Philippians 1:6" },
    { text: "And let us consider how to stir up one another to love and good works.", tamil: "அன்புகூரவும் நற்கிரியைகளைச் செய்யவும் நாம் ஏவப்படும்படி ஒருவரையொருவர் கவனித்து;", ref: "எபிரெயர் / Hebrews 10:24" },
    { text: "Finally, all of you, have unity of mind, sympathy, brotherly love, a tender heart, and a humble mind.", tamil: "முடிவாக, நீங்களெல்லாரும் ஏகசிந்தையுள்ளவர்களும், இரக்கமுள்ளவர்களும், சகோதர சிநேகமுள்ளவர்களும், மனஉருக்கமுள்ளவர்களும், இணக்கமுள்ளவர்களுமாயிருந்து;", ref: "பேதுரு 1 / 1 Peter 3:8" },
    { text: "A friend loves at all times, and a brother is born for adversity.", tamil: "சிநேகிதன் எல்லாக் காலத்திலும் சிநேகிப்பான்; இடுக்கணில் உதவவே சகோதரன் பிறந்திருக்கிறான்.", ref: "நீதிமொழிகள் / Proverbs 17:17" },
    { text: "I will instruct you and teach you in the way you should go; I will counsel you with my eye upon you.", tamil: "நான் உனக்குப் போதித்து, நீ நடக்கவேண்டிய வழியை உனக்குக் காட்டுவேன்; உன்மேல் என் கண்ணை வைத்து, உனக்கு ஆலோசனை சொல்லுவேன்.", ref: "சங்கீதம் / Psalm 32:8" },
    { text: "I have set the Lord always before me; because he is at my right hand, I shall not be shaken.", tamil: "கர்த்தரை எப்பொழுதும் எனக்கு முன்பாக வைத்திருக்கிறேன்; அவர் என் வலதுபாரிசத்தில் இருக்கிறபடியால் நான் அசைக்கப்படுவதில்லை.", ref: "சங்கீதம் / Psalm 16:8" },
    { text: "This is my commandment, that you love one another as I have loved you.", tamil: "நான் உங்களில் அன்பாயிருக்கிறதுபோல நீங்களும் ஒருவரிலொருவர் அன்பாயிருக்கவேண்டுமென்பதே என்னுடைய கற்பனையாயிருக்கிறது.", ref: "யோவான் / John 15:12" },
    { text: "The grace of the Lord Jesus Christ and the love of God and the fellowship of the Holy Spirit be with you all.", tamil: "கர்த்தராகிய இயேசுகிறிஸ்துவினுடைய கிருபையும், தேவனுடைய அன்பும், பரிசுத்த ஆவியினுடைய ஐக்கியமும், உங்கள் அனைவரோடுங்கூட இருப்பதாக. ஆமென்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 13:14" },
    { text: "Continue steadfastly in prayer, being watchful in it with thanksgiving.", tamil: "ஜெபத்திலே உறுதியாய்த் தரித்திருங்கள், ஸ்தோத்திரத்துடன் அதிலே விழித்திருங்கள்.", ref: "கொலோசெயர் / Colossians 4:2" },
    { text: "Therefore, confess your sins to one another and pray for one another, that you may be healed.", tamil: "நீங்கள் சொஸ்தமடையும்படிக்கு, உங்கள் குற்றங்களை ஒருவருக்கொருவர் அறிக்கையிட்டு, ஒருவருக்காக ஒருவர் ஜெபம்பண்ணுங்கள்...", ref: "யாக்கோபு / James 5:16" },
    { text: "And this is the confidence that we have toward him, that if we ask anything according to his will he hears us.", tamil: "நாம் எதையாகிலும் அவருடைய சித்தத்தின்படி கேட்டால், அவர் நமக்குச் செவிகொடுக்கிறாரென்பதே அவரைப் பற்றி நாம் கொண்டிருக்கிற தைரியம்.", ref: "யோவான் 1 / 1 John 5:14" },
    { text: "This is the day that the Lord has made; let us rejoice and be glad in it.", tamil: "இதோ, இது கர்த்தர் உண்டுபண்ணின நாள்; இதிலே களிகூர்ந்து மகிழக்கடவோம்.", ref: "சங்கீதம் / Psalm 118:24" },
    { text: "May the God of endurance and encouragement grant you to live in such harmony with one another, in accord with Christ Jesus.", tamil: "நீங்கள் ஒருவரையொருவர் கிறிஸ்து இயேசுவுக்கேற்றபடியாய்ச் சிந்திக்கிற சிந்தையுள்ளவர்களாயிருக்கும்படி, பொறுமையையும் ஆறுதலையும் அளிக்கும் தேவன் உங்களுக்கு அநுக்கிரகஞ்செய்வாராக.", ref: "ரோமர் / Romans 15:5" },
    { text: "God is faithful, by whom you were called into the fellowship of his Son, Jesus Christ our Lord.", tamil: "நம்முடைய கர்த்தராயிருக்கிற இயேசுகிறிஸ்து என்னும் தம்முடைய குமாரனுடைய ஐக்கியத்திற்கு உங்களை அழைத்த தேவன் உண்மையுள்ளவர்.", ref: "கொரிந்தியர் 1 / 1 Corinthians 1:9" },
    { text: "The Lord is my strength and my shield; in him my heart trusts, and I am helped; my heart exults, and with my song I give thanks to him.", tamil: "கர்த்தர் என் பெலனும் என் கேடகமுமாயிருக்கிறார்; என் இருதயம் அவரை நம்பியிருந்தது; நான் சகாயம்பெற்றேன், ஆகையால் என் இருதயம் களிகூருகிறது; என் பாட்டினால் அவரைத் துதிப்பேன்.", ref: "சங்கீதம் / Psalm 28:7" },
        // --- MONTH 6 (Days 152-181) ---
    { text: "May he give you the desire of your heart and make all your plans succeed.", tamil: "உமது மனவிருப்பத்தின்படி அவர் உமக்குத் தந்தருளி, உமது ஆலோசனைகளையெல்லாம் நிறைவேற்றுவாராக.", ref: "சங்கீதம் / Psalm 20:4" },
    { text: "Delight yourself in the Lord, and he will give you the desires of your heart.", tamil: "கர்த்தரிடத்தில் மனமகிழ்ச்சியாயிரு; அவர் உன் இருதயத்தின் வேண்டுதல்களை உனக்கு அருள்செய்வார்.", ref: "சங்கீதம் / Psalm 37:4" },
    { text: "Gracious words are like a honeycomb, sweetness to the soul and health to the body.", tamil: "இனிய சொற்கள் தேன்கூடுபோல் ஆத்துமாவுக்கு மதுரமும், எலும்புகளுக்கு ஔஷதமுமாகும்.", ref: "நீதிமொழிகள் / Proverbs 16:24" },
    { text: "For I am sure that neither death nor life... will be able to separate us from the love of God in Christ Jesus our Lord.", tamil: "மரணமானாலும், ஜீவனானாலும்... கர்த்தராகிய கிறிஸ்து இயேசுவிலுள்ள தேவனுடைய அன்பைவிட்டு நம்மைப் பிரிக்கமாட்டாதென்று நிச்சயித்திருக்கிறேன்.", ref: "ரோமர் / Romans 8:38-39" },
    { text: "Rejoice in the Lord always; again I will say, rejoice.", tamil: "கர்த்தருக்குள் எப்பொழுதும் சந்தோஷமாயிருங்கள்; சந்தோஷமாயிருங்கள் என்று மறுபடியும் சொல்லுகிறேன்.", ref: "பிலிப்பியர் / Philippians 4:4" },
    { text: "Beloved, let us love one another, for love is from God, and whoever loves has been born of God and knows God.", tamil: "பிரியமானவர்களே, ஒருவரிலொருவர் அன்பாயிருக்கக்கடவோம்; ஏனெனில் அன்பு தேவனால் உண்டாயிருக்கிறது.", ref: "யோவான் 1 / 1 John 4:7" },
    { text: "Let me hear in the morning of your steadfast love, for in you I trust. Make me know the way I should go, for to you I lift up my soul.", tamil: "அதிகாலையில் உமது கிருபையைக் கேட்கப்பண்ணும், உம்மை நம்பியிருக்கிறேன்; நான் நடக்கவேண்டிய வழியை எனக்குக் காண்பியும்.", ref: "சங்கீதம் / Psalm 143:8" },
    { text: "My son, do not despise the Lord's discipline or be weary of his reproof.", tamil: "என் மகனே, நீ கர்த்தருடைய சிட்சையை அற்பமாக எண்ணாதே; அவர் கடிந்துகொள்ளும்போது சோர்ந்துபோகாதே.", ref: "நீதிமொழிகள் / Proverbs 3:11" },
    { text: "Trust in the Lord forever, for the Lord God is an everlasting rock.", tamil: "கர்த்தரை என்றென்றைக்கும் நம்புங்கள்; கர்த்தராகிய யேகோவா நித்திய கன்மலையாயிருக்கிறார்.", ref: "ஏசாயா / Isaiah 26:4" },
    { text: "You are the light of the world. A city set on a hill cannot be hidden.", tamil: "நீங்கள் உலகத்துக்கு வெளிச்சமாயிருக்கிறீர்கள்; மலையின்மேல் இருக்கிற பட்டணம் மறைந்திருக்கமாட்டாது.", ref: "மத்தேயு / Matthew 5:14" },
    { text: "My sheep hear my voice, and I know them, and they follow me.", tamil: "என் ஆடுகள் என் சத்தத்திற்குச் செவிகொடுக்கிறது; நான் அவைகளை அறிந்திருக்கிறேன், அவைகள் என்னைப் பின்பற்றுகிறது.", ref: "யோவான் / John 10:27" },
    { text: "But God shows his love for us in that while we were still sinners, Christ died for us.", tamil: "நாம் பாவிகளாயிருக்கையில் கிறிஸ்து நமக்காக மரித்ததினாலே, தேவன் நம்மேல் வைத்த தமது அன்பை விளங்கப்பண்ணுகிறார்.", ref: "ரோமர் / Romans 5:8" },
    { text: "And God is able to make all grace abound to you, so that having all sufficiency in all things at all times, you may abound in every good work.", tamil: "நீங்கள் எல்லாவற்றிலும் எப்பொழுதும் சம்பூரணமுடையவர்களாயும், சகலவித நற்கிரியைகளிலும் பெருகுகிறவர்களாயுமிருக்கும்படியாக தேவன் உங்களிடத்தில் சகலவித கிருபையையும் பெருகச்செய்ய வல்லவராயிருக்கிறார்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 9:8" },
    { text: "Bear one another's burdens, and so fulfill the law of Christ.", tamil: "ஒருவர் பாரத்தை ஒருவர் சுமந்து, இப்படியே கிறிஸ்துவினுடைய பிரமாணத்தை நிறைவேற்றுங்கள்.", ref: "கலாத்தியர் / Galatians 6:2" },
    { text: "With all humility and gentleness, with patience, bearing with one another in love.", tamil: "மிகுந்த மனத்தாழ்மையும் சாந்தமும் நீடிய பொறுமையும் உடையவர்களாய், அன்பினால் ஒருவரையொருவர் தாங்கி;", ref: "எபேசியர் / Ephesians 4:2" },
    { text: "Let the word of Christ dwell in you richly, teaching and admonishing one another in all wisdom.", tamil: "கிறிஸ்துவின் வசனம் உங்களுக்குள்ளே சகல ஞானத்தோடும் பரிபூரணமாக வாசமாயிருப்பதாக.", ref: "கொலோசெயர் / Colossians 3:16" },
    { text: "See that no one repays anyone evil for evil, but always seek to do good to one another and to everyone.", tamil: "ஒருவனும் மற்றொருவன் செய்யும் தீமைக்குத் தீமைசெய்யாதபடிக்குச் பார்த்து, உங்களுக்குள்ளும் மற்றெல்லாருக்குள்ளும் எப்பொழுதும் நன்மைசெய்ய நாடுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:15" },
    { text: "And without faith it is impossible to please him, for whoever would draw near to God must believe that he exists and that he rewards those who seek him.", tamil: "விசுவாசமில்லாமல் தேவனுக்குப் பிரியமாயிருப்பது கூடாதகாரியம்; ஏனெனில் தேவனிடத்தில் சேருகிறவன் அவர் உண்டென்றும், அவர் தம்மைத் தேடுகிறவர்களுக்குப் பலனளிக்கிறவரென்றும் விசுவாசிக்கவேண்டும்.", ref: "எபிரெயர் / Hebrews 11:6" },
    { text: "If any of you lacks wisdom, let him ask God, who gives generously to all without reproach, and it will be given him.", tamil: "உங்களில் ஒருவன் ஞானத்தில் குறைவுள்ளவனாயிருந்தால், யாவருக்கும் சம்பூரணமாய்க் கொடுக்கிறவரும் ஒருவரையும் கடிந்துகொள்ளாதவருமாகிய தேவனிடத்தில் கேட்கக்கடவன், அப்பொழுது அவனுக்குக் கொடுக்கப்படும்.", ref: "யாக்கோபு / James 1:5" },
    { text: "Humble yourselves, therefore, under the mighty hand of God so that at the proper time he may exalt you.", tamil: "ஆகையால், ஏற்றகாலத்திலே தேவன் உங்களை உயர்த்தும்படிக்கு, அவருடைய பலத்த கைக்குள் அடங்கியிருங்கள்.", ref: "பேதுரு 1 / 1 Peter 5:6" },
    { text: "If we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.", tamil: "நம்முடைய பாவங்களை நாம் அறிக்கையிட்டால், பாவங்களை நமக்கு மன்னித்து எவ்வித அநியாயமு நீங்க நம்மைச் சுத்திகரிப்பதற்கு அவர் உண்மையு நீதியுமுள்ளவராயிருக்கிறார்.", ref: "யோவான் 1 / 1 John 1:9" },
    { text: "Be strong, and let your heart take courage, all you who wait for the Lord!", tamil: "கர்த்தருக்குக் காத்திருக்கிறவர்களே, நீங்கள் எல்லாரும் திடமனதாயிருங்கள், அவர் உங்கள் இருதயத்தை ஸ்திரப்படுத்துவார்.", ref: "சங்கீதம் / Psalm 31:24" },
    { text: "Forever, O Lord, your word is firmly fixed in the heavens.", tamil: "கர்த்தாவே, உமது வசனம் என்றென்றைக்கும் வானங்களில் நிலைத்திருக்கிறது.", ref: "சங்கீதம் / Psalm 119:89" },
    { text: "A soft answer turns away wrath, but a harsh word stirs up anger.", tamil: "மெதுவான பிரதியுத்தரம் உக்கிரத்தை மாற்றும்; கடுஞ்சொல்லோ கோபத்தை எழுப்பும்.", ref: "நீதிமொழிகள் / Proverbs 15:1" },
    { text: "The grass withers, the flower fades, but the word of our God will stand forever.", tamil: "புல் உலர்ந்து பூ உதிரும்; நமது தேவனுடைய வசனமோ என்றென்றைக்கும் நிற்கும்.", ref: "ஏசாயா / Isaiah 40:8" },
    { text: "Behold, I am the Lord, the God of all flesh. Is anything too hard for me?", tamil: "இதோ, நான் மாம்சமான யாவருக்கும் தேவனாகிய கர்த்தர்; என்னாலே செய்யக்கூடாத அதிசயமான காரியம் ஒன்றுண்டோ?", ref: "எரேமியா / Jeremiah 32:27" },
    { text: "Not by might, nor by power, but by my Spirit, says the Lord of hosts.", tamil: "பலத்தினாலும் அல்ல, பராக்கிரமத்தினாலும் அல்ல, என்னுடைய ஆவியினாலேயே ஆகும் என்று சேனைகளின் கர்த்தர் சொல்லுகிறார்.", ref: "சகரியா / Zechariah 4:6" },
    { text: "Take my yoke upon you, and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls.", tamil: "நான் சாந்தமும் மனத்தாழ்மையுமாயிருக்கிறேன்; என் நுகத்தை உங்கள்மேல் ஏற்றுக்கொண்டு, என்னிடத்தில் கற்றுக்கொள்ளுங்கள்; அப்பொழுது, உங்கள் ஆத்துமாக்களுக்கு இளைப்பாறுதல் கிடைக்கும்.", ref: "மத்தேயு / Matthew 11:29" },
    { text: "I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit, for apart from me you can do nothing.", tamil: "நானே திராட்சச்செடி, நீங்கள் கொடிகள். ஒருவன் என்னிலும் நான் அவனிலும் நிலைத்திருந்தால், அவன் மிகுந்த கனிகளைத் தருவான்; என்னையல்லாமல் உங்களால் ஒன்றும் செய்யக்கூடாது.", ref: "யோவான் / John 15:5" },
    { text: "Do not be overcome by evil, but overcome evil with good.", tamil: "நீ தீமையினாலே வெல்லப்படாமல், தீமையை நன்மையினாலே வெல்லு.", ref: "ரோமர் / Romans 12:21" },
        // --- MONTH 7 (Days 182-211) ---
    { text: "For God so loved the world, that he gave his only Son, that whoever believes in him should not perish but have eternal life.", tamil: "தேவன், தம்முடைய ஒரேபேறான குமாரனை விசுவாசிக்கிறவன் எவனோ அவன் கெட்டுப்போகாமல் நித்தியஜீவனை அடையும்படிக்கு, அவரைத் தந்தருளி, இவ்வளவாய் உலகத்தில் அன்புகூர்ந்தார்.", ref: "யோவான் / John 3:16" },
    { text: "Be still, and know that I am God. I will be exalted among the nations, I will be exalted in the earth!", tamil: "நீங்கள் அமர்ந்திருந்து, நானே தேவனென்று அறிந்துகொள்ளுங்கள்; ஜாதிகளுக்குள்ளே உயர்ந்திருப்பேன், பூமியிலே உயர்ந்திருப்பேன்.", ref: "சங்கீதம் / Psalm 46:10" },
    { text: "Surely goodness and mercy shall follow me all the days of my life, and I shall dwell in the house of the Lord forever.", tamil: "என் ஜீவனுள்ள நாளெல்லாம் நன்மையும் கிருபையும் என்னைத் தொடரும்; நான் கர்த்தருடைய வீட்டிலே நீடித்த நாட்களாய் நிலைத்திருப்பேன்.", ref: "சங்கீதம் / Psalm 23:6" },
    { text: "Therefore, if anyone is in Christ, he is a new creation. The old has passed away; behold, the new has come.", tamil: "இப்படியிருக்க, ஒருவன் கிறிஸ்துவுக்குள்ளிருந்தால் புதுச்சிருஷ்டியாயிருக்கிறான்; பழையவைகள் ஒழிந்துபோயின, எல்லாம் புதிதாயின.", ref: "கொரிந்தியர் 2 / 2 Corinthians 5:17" },
    { text: "I appeal to you therefore, brothers, by the mercies of God, to present your bodies as a living sacrifice, holy and acceptable to God...", tamil: "அன்றியும் சகோதரரே, நீங்கள் உங்கள் சரீரங்களைப் பரிசுத்தமும் தேவனுக்குப் பிரியமுமான ஜீவபலியாக ஒப்புக்கொடுக்கவேண்டுமென்று, தேவனுடைய இரக்கங்களை முன்னிட்டு உங்களை வேண்டிக்கொள்ளுகிறேன்...", ref: "ரோமர் / Romans 12:1" },
    { text: "Therefore, since we are surrounded by so great a cloud of witnesses, let us also lay aside every weight, and sin which clings so closely...", tamil: "ஆகையால், மேகம்போன்ற இத்தனை திரளான சாட்சிகள் நம்மைச் சூழ்ந்துகொண்டிருக்க, பாரமான யாவற்றையும், நம்மைச் சுற்றி நெருங்கிநிற்கிற பாவத்தையும் தள்ளிவிட்டு...", ref: "எபிரெயர் / Hebrews 12:1" },
    { text: "Looking to Jesus, the founder and perfecter of our faith, who for the joy that was set before him endured the cross...", tamil: "அவர் தமக்குமுன் வைத்திருந்த சந்தோஷத்தின்பொருட்டு, அவமானத்தை எண்ணாமல், சிலுவையைச் சகித்து, தேவனுடைய சிங்காசனத்தின் வலதுபாரிசத்தில் வீற்றிருக்கிறார்.", ref: "எபிரெயர் / Hebrews 12:2" },
    { text: "Count it all joy, my brothers, when you meet trials of various kinds...", tamil: "என் சகோதரரே, நீங்கள் பலவிதமான சோதனைகளில் அகப்படும்போது அதை மிகுந்த சந்தோஷமாக எண்ணுங்கள்.", ref: "யாக்கோபு / James 1:2" },
    { text: "For you know that the testing of your faith produces steadfastness.", tamil: "உங்கள் விசுவாசத்தின் பரீட்சையானது பொறுமையை உண்டாக்குமென்று அறிந்து...", ref: "யாக்கோபு / James 1:3" },
    { text: "Be sober-minded; be watchful. Your adversary the devil prowls around like a roaring lion, seeking someone to devour.", tamil: "தெளிந்த புத்தியுள்ளவர்களாயிருங்கள், விழித்திருங்கள்; ஏனெனில், உங்கள் எதிராளியாகிய பிசாசானவன் கெர்ச்சிக்கிற சிங்கம்போல் எவனை விழுங்கலாமோ என்று வகைதேடிச் சுற்றித்திரிகிறான்.", ref: "பேதுரு 1 / 1 Peter 5:8" },
    { text: "But if we walk in the light, as he is in the light, we have fellowship with one another, and the blood of Jesus his Son cleanses us from all sin.", tamil: "அவர் ஒளியிலிருக்கிறதுபோல நாமும் ஒளியிலே நடந்தால் ஒருவரோடொருவர் ஐக்கியப்பட்டிருப்போம்; அவருடைய குமாரனாகிய இயேசுகிறிஸ்துவின் இரத்தம் சகல பாவங்களையும் நீக்கி, நம்மைச் சுத்திகரிக்கும்.", ref: "யோவான் 1 / 1 John 1:7" },
    { text: "Behold, I stand at the door and knock. If anyone hears my voice and opens the door, I will come in to him and eat with him, and he with me.", tamil: "இதோ, வாசற்படியிலே நின்று தட்டுகிறேன்; ஒருவன் என் சத்தத்தைக்கேட்டு, கதவைத் திறந்தால், அவனிடத்தில் நான் பிரவேசித்து, அவனோடே போஜனம்பண்ணுவேன், அவனும் என்னோடே போஜனம்பண்ணுவான்.", ref: "வெளிப்படுத்தின விசேஷம் / Revelation 3:20" },
    { text: "For to us a child is born, to us a son is given; and the government shall be upon his shoulder...", tamil: "நமக்கு ஒரு பாலகன் பிறந்தார்; நமக்கு ஒரு குமாரன் கொடுக்கப்பட்டார்; கர்த்தத்துவம் அவர் தோளின்மேலிருக்கும்...", ref: "ஏசாயா / Isaiah 9:6" },
    { text: "But he was pierced for our transgressions; he was crushed for our iniquities; upon him was the chastisement that brought us peace...", tamil: "நம்முடைய மீறுதல்களினிமித்தம் அவர் காயப்பட்டு, நம்முடைய அக்கிரமங்களினிமித்தம் அவர் நொறுக்கப்பட்டார்; நமக்குச் சமாதானத்தை உண்டுபண்ணும் ஆக்கினை அவர்மேல் வந்தது...", ref: "ஏசாயா / Isaiah 53:5" },
    { text: "Jesus looked at them and said, 'With man it is impossible, but not with God. For all things are possible with God.'", tamil: "இயேசு அவர்களைப் பார்த்து: மனுஷரால் இது கூடாததுதான், தேவனால் இது கூடாததல்ல; தேவனாலே எல்லாம் கூடும் என்றார்.", ref: "மாற்கு / Mark 10:27" },
    { text: "For nothing will be impossible with God.", tamil: "தேவனால் கூடாத காரியம் ஒன்றுமில்லை என்றான்.", ref: "லூக்கா / Luke 1:37" },
    { text: "Again Jesus spoke to them, saying, 'I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life.'", tamil: "மறுபடியும் இயேசு ஜனங்களை நோக்கி: நான் உலகத்திற்கு ஒளியாயிருக்கிறேன், என்னைப் பின்பற்றுகிறவன் இருளிலே நடவாமல் ஜீவஒளியை அடைந்திருப்பான் என்றார்.", ref: "யோவான் / John 8:12" },
    { text: "Jesus said to her, 'I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live.'", tamil: "இயேசு அவளை நோக்கி: நானே உயிர்த்தெழுதலும் ஜீவனுமாயிருக்கிறேன், என்னை விசுவாசிக்கிறவன் மரித்தாலும் பிழைப்பான்.", ref: "யோவான் / John 11:25" },
    { text: "But you will receive power when the Holy Spirit has come upon you, and you will be my witnesses in Jerusalem and in all Judea and Samaria...", tamil: "பரிசுத்த ஆவி உங்களிடத்தில் வரும்போது நீங்கள் பெலனடைந்து, எருசலேமிலும், யூதேயா முழுவதிலும், சமாரியாவிலும்... எனக்குச் சாட்சிகளாயிருப்பீர்கள் என்றார்.", ref: "அப்போஸ்தலர் / Acts 1:8" },
    { text: "For all have sinned and fall short of the glory of God.", tamil: "எல்லாரும் பாவஞ்செய்து, தேவமகிமையற்றவர்களாகி,", ref: "ரோமர் / Romans 3:23" },
    { text: "For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord.", tamil: "பாவத்தின் சம்பளம் மரணம்; தேவனுடைய கிருபைவரமோ நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவினால் உண்டான நித்தியஜீவன்.", ref: "ரோமர் / Romans 6:23" },
    { text: "Create in me a clean heart, O God, and renew a right spirit within me.", tamil: "தேவனே, சுத்த இருதயத்தை என்னிலே சிருஷ்டியும், நிலைவரமான ஆவியை என் உள்ளத்திலே புதுப்பியும்.", ref: "சங்கீதம் / Psalm 51:10" },
    { text: "He has told you, O man, what is good; and what does the Lord require of you but to do justice, and to love kindness, and to walk humbly with your God?", tamil: "மனுஷனே, நன்மை இன்னதென்று அவர் உனக்கு அறிவித்திருக்கிறார்; நியாயஞ்செய்து, இரக்கத்தைச் சிநேகித்து, உன் தேவனுக்கு முன்பாக மனத்தாழ்மையாய் நடப்பதை அல்லாமல் வேறே என்னத்தைக் கர்த்தர் உன்னிடத்தில் கேட்கிறார்.", ref: "மீகா / Micah 6:8" },
    { text: "No temptation has overtaken you that is not common to man. God is faithful, and he will not let you be tempted beyond your ability...", tamil: "மனுஷருக்கு நேரிடுகிற சோதனையேயல்லாமல் வேறே சோதனை உங்களுக்கு நேரிடவில்லை. தேவன் உண்மையுள்ளவராயிருக்கிறார்; உங்கள் திராணிக்கு மேலாக நீங்கள் சோதிக்கப்படுகிறதற்கு அவர் இடங்கொடாமல்...", ref: "கொரிந்தியர் 1 / 1 Corinthians 10:13" },
    { text: "But he said to me, 'My grace is sufficient for you, for my power is made perfect in weakness.'", tamil: "அதற்கு அவர்: என் கிருபை உனக்குப் போதும்; பலவீனத்திலே என் பலம் பூரணமாய் விளங்கும் என்றார்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 12:9" },
    { text: "Put on the whole armor of God, that you may be able to stand against the schemes of the devil.", tamil: "நீங்கள் பிசாசின் தந்திரங்களோடு எதிர்த்துநிற்கத் திராணியுள்ளவர்களாகும்படி, தேவனுடைய சர்வாயுதவர்க்கத்தையும் தரித்துக்கொள்ளுங்கள்.", ref: "எபேசியர் / Ephesians 6:11" },
    { text: "Set your minds on things that are above, not on things that are on earth.", tamil: "பூமியிலுள்ளவைகளையல்ல, மேலானவைகளையே நாடுங்கள்.", ref: "கொலோசெயர் / Colossians 3:2" },
    { text: "All Scripture is breathed out by God and profitable for teaching, for reproof, for correction, and for training in righteousness.", tamil: "வேதவாக்கியங்களெல்லாம் தேவ ஆவியினால் அருளப்பட்டிருக்கிறது...", ref: "தீமோத்தேயு 2 / 2 Timothy 3:16" },
    { text: "For the Lord himself will descend from heaven with a cry of command, with the voice of an archangel, and with the sound of the trumpet of God.", tamil: "ஏனெனில், கர்த்தர் தாமே ஆரவாரத்தோடும், பிரதான தூதனுடைய சத்தத்தோடும், தேவ எக்காளத்தோடும் வானத்திலிருந்து இறங்கிவருவார்...", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 4:16" },
    { text: "A man of many companions may come to ruin, but there is a friend who sticks closer than a brother.", tamil: "சிநேகிதருள்ளவன் சிநேகம்பண்ணவேண்டும்; சகோதரனிலும் அதிகமாய் நேசிக்கிற சிநேகிதனுமுண்டு.", ref: "நீதிமொழிகள் / Proverbs 18:24" },
        // --- MONTH 8 (Days 212-241) ---
    { text: "The Lord will fight for you, and you have only to be silent.", tamil: "கர்த்தர் உங்களுக்காக யுத்தம்பண்ணுவார்; நீங்கள் சும்மாயிருப்பீர்கள் என்றான்.", ref: "யாத்திராகமம் / Exodus 14:14" },
    { text: "You shall love the Lord your God with all your heart and with all your soul and with all your might.", tamil: "உன் தேவனாகிய கர்த்தரிடத்தில் உன் முழு இருதயத்தோடும், உன் முழு ஆத்துமாவோடும், உன் முழுப் பலத்தோடும் அன்புகூருவாயாக.", ref: "உபாகமம் / Deuteronomy 6:5" },
    { text: "The heavens declare the glory of God, and the sky above proclaims his handiwork.", tamil: "வானங்கள் தேவனுடைய மகிமையை வெளிப்படுத்துகிறது, ஆகாயவிரிவு அவருடைய கரங்களின் கிரியையை அறிவிக்கிறது.", ref: "சங்கீதம் / Psalm 19:1" },
    { text: "One thing have I asked of the Lord, that will I seek after...", tamil: "நான் கர்த்தரிடத்தில் ஒன்றைக் கேட்டேன், அதையே நாடுவேன்...", ref: "சங்கீதம் / Psalm 27:4" },
    { text: "For the Lord God is a sun and shield; the Lord bestows favor and honor.", tamil: "தேவனாகிய கர்த்தர் சூரியனும் கேடகமுமானவர்; கர்த்தர் கிருபையையும் மகிமையையும் அருளுவார்...", ref: "சங்கீதம் / Psalm 84:11" },
    { text: "Search me, O God, and know my heart! Try me and know my thoughts!", tamil: "தேவனே, என்னை ஆராய்ந்து, என் இருதயத்தை அறிந்துகொள்ளும்...", ref: "சங்கீதம் / Psalm 139:23" },
    { text: "When you pass through the waters, I will be with you; and through the rivers, they shall not overwhelm you...", tamil: "நீ தண்ணீர்களைக் கடக்கும்போது நான் உன்னோடு இருப்பேன்...", ref: "ஏசாயா / Isaiah 43:2" },
    { text: "For where your treasure is, there your heart will be also.", tamil: "உங்கள் பொக்கிஷம் எங்கே இருக்கிறதோ அங்கே உங்கள் இருதயமும் இருக்கும்.", ref: "மத்தேயு / Matthew 6:21" },
    { text: "Go therefore and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit.", tamil: "ஆகையால், நீங்கள் புறப்பட்டுப்போய், சகல ஜாதிகளையும் சீஷராக்கி...", ref: "மத்தேயு / Matthew 28:19" },
    { text: "If anyone would come after me, let him deny himself and take up his cross daily and follow me.", tamil: "ஒருவன் என் பின்னே வர விரும்பினால், அவன் தன்னைத்தான் வெறுத்து, தன் சிலுவையை அநுதினமும் எடுத்துக்கொண்டு, என்னைப் பின்பற்றக்கடவன்.", ref: "லூக்கா / Luke 9:23" },
    { text: "In the beginning was the Word, and the Word was with God, and the Word was God.", tamil: "ஆதியிலே வார்த்தை இருந்தது, அந்த வார்த்தை தேவனிடத்திலிருந்தது, அந்த வார்த்தை தேவனாயிருந்தது.", ref: "யோவான் / John 1:1" },
    { text: "The thief comes only to steal and kill and destroy. I came that they may have life and have it abundantly.", tamil: "திருடன் திருடவும் கொல்லவும் அழிக்கவும் வருகிறானேயன்றி வேறொன்றுக்கும் வரான். நானோ அவைகளுக்கு ஜீவன் உண்டாயிருக்கவும், அது பரிபூரணப்படவும் வந்தேன்.", ref: "யோவான் / John 10:10" },
    { text: "Therefore, since we have been justified by faith, we have peace with God through our Lord Jesus Christ.", tamil: "இவ்விதமாக, நாம் விசுவாசத்தினாலே நீதிமான்களாக்கப்பட்டிருக்கிறபடியால், நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துமூலமாய் தேவனிடத்தில் சமாதானம் பெற்றிருக்கிறோம்.", ref: "ரோமர் / Romans 5:1" },
    { text: "There is therefore now no condemnation for those who are in Christ Jesus.", tamil: "ஆனபடியால், கிறிஸ்து இயேசுவுக்குட்பட்டவர்களாயிருந்து, மாம்சத்தின்படி நடவாமல் ஆவியின்படியே நடக்கிறவர்களுக்கு ஆக்கினைத்தீர்ப்பில்லை.", ref: "ரோமர் / Romans 8:1" },
    { text: "Let love be genuine. Abhor what is evil; hold fast to what is good.", tamil: "உங்கள் அன்பு மாயமற்றதாயிருப்பதாக; தீமையை வெறுத்து, நன்மையைப் பற்றிக்கொண்டிருங்கள்.", ref: "ரோமர் / Romans 12:9" },
    { text: "So now faith, hope, and love abide, these three; but the greatest of these is love.", tamil: "இப்பொழுது விசுவாசம், நம்பிக்கை, அன்பு இம்மூன்றும் நிலைத்திருக்கிறது; இவைகளில் அன்பே பெரியது.", ref: "கொரிந்தியர் 1 / 1 Corinthians 13:13" },
    { text: "And whatever you do, in word or deed, do everything in the name of the Lord Jesus, giving thanks to God the Father through him.", tamil: "வார்த்தையினாலாவது கிரியையினாலாவது, நீங்கள் எதைச் செய்தாலும், அதையெல்லாம் கர்த்தராகிய இயேசுவின் நாமத்தினாலே செய்து, அவர் முன்னிலையாகப் பிதாவாகிய தேவனை ஸ்தோத்தரியுங்கள்.", ref: "கொலோசெயர் / Colossians 3:17" },
    { text: "Let us then with confidence draw near to the throne of grace, that we may receive mercy and find grace to help in time of need.", tamil: "ஆதலால், நாம் இரக்கத்தைப் பெறவும், ஏற்ற சமயத்தில் சகாயஞ்செய்யுங் கிருபையை அடையவும், தைரியமாய்க் கிருபாசனத்தண்டையிலே சேரக்கடவோம்.", ref: "எபிரெயர் / Hebrews 4:16" },
    { text: "Let us hold fast the confession of our hope without wavering, for he who promised is faithful.", tamil: "அல்லாமலும், நம்முடைய நம்பிக்கையை அறிக்கையிடுகிறதில் அசைவில்லாமல் உறுதியாயிருக்கக்கடவோம்; வாக்குத்தத்தம்பண்ணினவர் உண்மையுள்ளவராயிருக்கிறாரே.", ref: "எபிரெயர் / Hebrews 10:23" },
    { text: "He himself bore our sins in his body on the tree, that we might die to sin and live to righteousness. By his wounds you have been healed.", tamil: "நாம் பாவங்களுக்குச் செத்து, நீதிக்குப் பிழைத்திருக்கும்படிக்கு, அவர்தாமே தமது சரீரத்திலே நம்முடைய பாவங்களைச் சிலுவையின்மேல் சுமந்தார்; அவருடைய தழும்புகளால் குணமானீர்கள்.", ref: "பேதுரு 1 / 1 Peter 2:24" },
    { text: "See what kind of love the Father has given to us, that we should be called children of God; and so we are.", tamil: "நாம் தேவனுடைய பிள்ளைகளென்று அழைக்கப்படுவதினாலே பிதாவானவர் நமக்குப் பாராட்டின அன்பு எவ்வளவு பெரிதென்று பாருங்கள்.", ref: "யோவான் 1 / 1 John 3:1" },
    { text: "Honor the Lord with your wealth and with the firstfruits of all your produce.", tamil: "உன் பொருளாஸ்தாரத்தினாலும், உன் எல்லா விளைவின் முதற்பலனினாலும் கர்த்தரைக் கனம்பண்ணு.", ref: "நீதிமொழிகள் / Proverbs 3:9" },
    { text: "He who dwells in the shelter of the Most High will abide in the shadow of the Almighty.", tamil: "உன்னதமானவரின் மறைவிலிருக்கிறவன் சர்வவல்லவருடைய நிழலில் தங்குவான்.", ref: "சங்கீதம் / Psalm 91:1" },
    { text: "Blessed are those whose way is blameless, who walk in the law of the Lord!", tamil: "கர்த்தருடைய வேதத்தின்படி நடக்கிற உத்தம மார்க்கத்தார் பாக்கியவான்கள்.", ref: "சங்கீதம் / Psalm 119:1" },
    { text: "The Lord is my portion, says my soul, therefore I will hope in him.", tamil: "கர்த்தர் என் பங்கு என்று என் ஆத்துமா சொல்லும்; ஆகையால் அவரிடத்தில் நம்பிக்கையாயிருப்பேன்.", ref: "புலம்பல் / Lamentations 3:24" },
    { text: "But the path of the righteous is like the light of dawn, which shines brighter and brighter until full day.", tamil: "நீதிமான்களுடைய பாதை நடுப்பகல்வரைக்கும் அதிகமதிகமாய்ப் பிரகாசிக்கிற சூரியப்பிரகாசம்போலிருக்கும்.", ref: "நீதிமொழிகள் / Proverbs 4:18" },
    { text: "For God alone my soul waits in silence; from him comes my salvation.", tamil: "என் ஆத்துமா தேவனை நோக்கி அமர்ந்திருக்கிறது; அவராலே என் இரட்சிப்பு வரும்.", ref: "சங்கீதம் / Psalm 62:1" },
    { text: "He will not let your foot be moved; he who keeps you will not slumber.", tamil: "உன் காலைத் தள்ளாடவொட்டார்; உன்னைக் காக்கிறவர் உறங்கார்.", ref: "சங்கீதம் / Psalm 121:3" },
    { text: "Give thanks to the Lord, for he is good, for his steadfast love endures forever.", tamil: "கர்த்தரைத் துதியுங்கள், அவர் நல்லவர்; அவர் கிருபை என்றுமுள்ளது.", ref: "சங்கீதம் / Psalm 136:1" },
    { text: "So we do not lose heart. Though our outer self is wasting away, our inner self is being renewed day by day.", tamil: "ஆனபடியினாலே நாங்கள் சோர்ந்துபோகிறதில்லை; எங்கள் புறம்பான மனுஷனானது அழிந்தும், உள்ளான மனுஷனானது நாளுக்குநாள் புதிதாக்கப்படுகிறது.", ref: "கொரிந்தியர் 2 / 2 Corinthians 4:16" },
    
        // --- MONTH 9 (Days 242-271) ---
    { text: "I will say to the Lord, 'My refuge and my fortress, my God, in whom I trust.'", tamil: "நான் கர்த்தரை நோக்கி: நீர் என் அடைக்கலமும், என் கோட்டையும், நான் நம்பியிருக்கிற என் தேவனும் என்று சொல்லுவேன்.", ref: "சங்கீதம் / Psalm 91:2" },
    { text: "He will tend his flock like a shepherd; he will gather the lambs in his arms...", tamil: "மேய்ப்பனைப்போலத் தமது மந்தையை மேய்ப்பார்; ஆட்டுக்குட்டிகளைத் தமது புயத்தினால் சேர்த்து...", ref: "ஏசாயா / Isaiah 40:11" },
    { text: "For my yoke is easy, and my burden is light.", tamil: "என் நுகம் மிருதுவாயும், என் சுமை இலகுவாயும் இருக்கிறது என்றார்.", ref: "மத்தேயு / Matthew 11:30" },
    { text: "No, in all these things we are more than conquerors through him who loved us.", tamil: "இவையெல்லாவற்றிலேயும் நாம் நம்மில் அன்புகூருகிறவராலே முற்றும் ஜெயங்கொள்ளுகிறவர்களாயிருக்கிறோமே.", ref: "ரோமர் / Romans 8:37" },
    { text: "Be watchful, stand firm in the faith, act like men, be strong.", tamil: "விழித்திருங்கள், விசுவாசத்திலே நிலைத்திருங்கள், புருஷராயிருங்கள், திடன்கொள்ளுங்கள்.", ref: "கொரிந்தியர் 1 / 1 Corinthians 16:13" },
    { text: "So as to walk in a manner worthy of the Lord, fully pleasing to him...", tamil: "சகலவித நற்கிரியைகளுமாகிய கனிகளைத் தந்து, தேவனை அறிகிற அறிவில் விருத்தியடைந்து, கர்த்தருக்குப் பிரியமுண்டாக அவருக்குப் பாத்திரராய் நடந்துகொள்ளவும்...", ref: "கொலோசெயர் / Colossians 1:10" },
    { text: "He who calls you is faithful; he will surely do it.", tamil: "உங்களை அழைக்கிறவர் உண்மையுள்ளவர், அவர் அப்படியே செய்வார்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:24" },
    { text: "Submit yourselves therefore to God. Resist the devil, and he will flee from you.", tamil: "ஆகையால், தேவனுக்குக் கீழ்ப்படிந்திருங்கள்; பிசாசுக்கு எதிர்த்து நில்லுங்கள், அப்பொழுது அவன் உங்களைவிட்டு ஓடிப்போவான்.", ref: "யாக்கோபு / James 4:7" },
    { text: "But in your hearts honor Christ the Lord as holy...", tamil: "கர்த்தராகிய தேவனை உங்கள் இருதயங்களில் பரிசுத்தம்பண்ணுங்கள்...", ref: "பேதுரு 1 / 1 Peter 3:15" },
    { text: "For everyone who has been born of God overcomes the world. And this is the victory that has overcome the world—our faith.", tamil: "தேவனால் பிறந்ததெல்லாம் உலகத்தை ஜெயிக்கும்; நம்முடைய விசுவாசமே உலகத்தை ஜெயிக்கிற ஜெயம்.", ref: "யோவான் 1 / 1 John 5:4" },
    { text: "He will wipe away every tear from their eyes, and death shall be no more...", tamil: "அவர்களுடைய கண்ணீர் யாவையும் தேவன் துடைப்பார்; இனி மரணமுமில்லை, துக்கமுமில்லை, அலறுதலுமில்லை, வருத்தமுமில்லை...", ref: "வெளிப்படுத்தின விசேஷம் / Revelation 21:4" },
    { text: "And he said, 'My presence will go with you, and I will give you rest.'", tamil: "அதற்கு அவர்: என் சமுகம் உனக்கு முன்பாகச் செல்லும், நான் உனக்கு இளைப்பாறுதல் தருவேன் என்றார்.", ref: "யாத்திராகமம் / Exodus 33:14" },
    { text: "It is the Lord who goes before you. He will be with you; he will not leave you or forsake you.", tamil: "கர்த்தர்தாமே உனக்கு முன்பாகப் போகிறவர், அவர் உன்னோடே இருப்பார்; அவர் உன்னை விட்டு விலகுவதுமில்லை, உன்னைக் கைவிடுவதுமில்லை...", ref: "உபாகமம் / Deuteronomy 31:8" },
    { text: "No man shall be able to stand before you all the days of your life. Just as I was with Moses, so I will be with you.", tamil: "நீ உயிரோடிருக்கும் நாளெல்லாம் ஒருவனும் உனக்கு முன்பாக எதிர்த்து நிற்பதில்லை; நான் மோசேயோடிருந்ததுபோல, உன்னோடும் இருப்பேன்...", ref: "யோசுவா / Joshua 1:5" },
    { text: "Only fear the Lord and serve him faithfully with all your heart.", tamil: "நீங்கள் கர்த்தருக்குப் பயந்து, உங்கள் முழு இருதயத்தோடும் உண்மையாய் அவரைச் சேவிக்கக்கடவீர்கள்...", ref: "சாமுவேல் 1 / 1 Samuel 12:24" },
    { text: "You make known to me the path of life; in your presence there is fullness of joy.", tamil: "ஜீவமார்க்கத்தை எனக்குத் தெரியப்படுத்துவீர்; உம்முடைய சமுகத்தில் பரிபூரண ஆனந்தமும், உம்முடைய வலதுபாரிசத்தில் நித்திய பேரின்பமும் உண்டு.", ref: "சங்கீதம் / Psalm 16:11" },
    { text: "You are a hiding place for me; you preserve me from trouble; you surround me with shouts of deliverance.", tamil: "நீர் எனக்கு மறைவிடமாயிருக்கிறீர்; நீர் என்னை இக்கட்டுக்கு விலக்கிக் காத்து, இரட்சணியப் பாடல்கள் என்னைச் சூழ்ந்துகொள்ளும்படி செய்வீர்.", ref: "சங்கீதம் / Psalm 32:7" },
    { text: "The Lord is near to the brokenhearted and saves the crushed in spirit.", tamil: "நொறுங்குண்ட இருதயமுள்ளவர்களுக்குக் கர்த்தர் சமீபமாயிருந்து, நருங்குண்ட ஆவியுள்ளவர்களை இரட்சிக்கிறார்.", ref: "சங்கீதம் / Psalm 34:18" },
    { text: "Cast your burden on the Lord, and he will sustain you; he will never permit the righteous to be moved.", tamil: "கர்த்தர்மேல் உன் பாரத்தை வைத்துவிடு, அவர் உன்னை ஆதரிப்பார்; நீதிமானை ஒருபோதும் தள்ளாடவொட்டார்.", ref: "சங்கீதம் / Psalm 55:22" },
    { text: "Keep steady my steps according to your promise, and let no iniquity get dominion over me.", tamil: "உமது வார்த்தையின்படி என் அடிகளை ஸ்திரப்படுத்தி, ஒரு அக்கிரமமும் என்னை ஆளவொட்டாதிரும்.", ref: "சங்கீதம் / Psalm 119:133" },
    { text: "Iron sharpens iron, and one man sharpens another.", tamil: "இரும்பை இரும்பு கருக்காக்கும்; அப்படியே மனுஷன் தன் சிநேகிதனுடைய முகத்தைக் கருக்காக்குவான்.", ref: "நீதிமொழிகள் / Proverbs 27:17" },
    { text: "For I, the Lord your God, hold your right hand; it is I who say to you, 'Fear not, I am the one who helps you.'", tamil: "உன் தேவனாகிய கர்த்தராயிருக்கிற நான் உன் வலதுகையைப் பிடித்து: பயப்படாதே, நான் உனக்குத் துணைநிற்கிறேன் என்று சொல்லுகிறேன்.", ref: "ஏசாயா / Isaiah 41:13" },
    { text: "Blessed are the pure in heart, for they shall see God.", tamil: "இருதயத்தில் சுத்தமுள்ளவர்கள் பாக்கியவான்கள்; அவர்கள் தேவனைத் தரிசிப்பார்கள்.", ref: "மத்தேயு / Matthew 5:8" },
    { text: "Therefore I tell you, whatever you ask in prayer, believe that you have received it, and it will be yours.", tamil: "ஆதலால், நீங்கள் ஜெபம்பண்ணும்போது எவைகளைக் கேட்டுக்கொள்வீர்களோ, அவைகளைப் பெற்றுக்கொள்வோம் என்று விசுவாசியுங்கள், அப்பொழுது அவைகள் உங்களுக்கு உண்டாகும்...", ref: "மாற்கு / Mark 11:24" },
    { text: "For I consider that the sufferings of this present time are not worth comparing with the glory that is to be revealed to us.", tamil: "ஆதலால் இக்காலத்துப் பாடுகள் இனி நம்மிடத்தில் வெளிப்படப்போகிற மகிமைக்கு ஒப்பிடத்தக்கவைகள் அல்லவென்று எண்ணுகிறேன்.", ref: "ரோமர் / Romans 8:18" },
    { text: "Because, if you confess with your mouth that Jesus is Lord and believe in your heart that God raised him from the dead, you will be saved.", tamil: "என்னவென்றால், கர்த்தராகிய இயேசுவை நீ உன் வாயினாலே அறிக்கையிட்டு, தேவன் அவரை மரித்தோரிலிருந்து எழுப்பினாரென்று உன் இருதயத்திலே விசுவாசித்தால் இரட்சிக்கப்படுவாய்.", ref: "ரோமர் / Romans 10:9" },
    { text: "Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort.", tamil: "நமது கர்த்தராகிய இயேசுகிறிஸ்துவின் பிதாவாகிய தேவனும், இரக்கங்களின் பிதாவாயும் சகலவிதமான ஆறுதலின் தேவனாயுமிருக்கிறவருக்கு ஸ்தோத்திரம்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 1:3" },
    { text: "Now to him who is able to do far more abundantly than all that we ask or think, according to the power at work within us.", tamil: "நாம் வேண்டிக்கொள்ளுகிறதற்கும் நினைக்கிறதற்கும் மிகவும் அதிகமாய் நமக்குள்ளே கிரியைசெய்கிற வல்லமையின்படியே, நமக்குச் செய்ய வல்லவருக்கு...", ref: "எபேசியர் / Ephesians 3:20" },
    { text: "For to me to live is Christ, and to die is gain.", tamil: "கிறிஸ்து எனக்கு ஜீவன், சாவு எனக்கு ஆதாயம்.", ref: "பிலிப்பியர் / Philippians 1:21" },
    { text: "Jesus Christ is the same yesterday and today and forever.", tamil: "இயேசுகிறிஸ்து நேற்றும் இன்றும் என்றென்றைக்கும் மாறாதவராயிருக்கிறார்.", ref: "எபிரெயர் / Hebrews 13:8" },
        // --- MONTH 10 (Days 272-301) ---
    { text: "The Lord will keep your going out and your coming in from this time forth and forevermore.", tamil: "கர்த்தர் உன் போக்கையும் உன் வரத்தையும் இதுமுதற்கொண்டு என்றென்றைக்கும் காப்பார்.", ref: "சங்கீதம் / Psalm 121:8" },
    { text: "If you lie down, you will not be afraid; when you lie down, your sleep will be sweet.", tamil: "நீ படுக்கும்போது பயப்படாதிருப்பாய்; நீ படுத்துக்கொள்ளும்போது உன் நித்திரை இன்பமாயிருக்கும்.", ref: "நீதிமொழிகள் / Proverbs 3:24" },
    { text: "Though your sins are like scarlet, they shall be as white as snow...", tamil: "உங்கள் பாவங்கள் சிவேரென்றிருந்தாலும் உறைந்த மழையைப்போல் வெண்மையாகும்...", ref: "ஏசாயா / Isaiah 1:18" },
    { text: "Before I formed you in the womb I knew you, and before you were born I consecrated you...", tamil: "நான் உன்னைத் தாயின் வயிற்றில் உருவாக்கு முன்னே உன்னை அறிந்தேன்; நீ கர்ப்பத்திலிருந்து வெளிப்படுமுன்னே நான் உன்னைப் பரிசுத்தம்பண்ணி...", ref: "எரேமியா / Jeremiah 1:5" },
    { text: "Heaven and earth will pass away, but my words will not pass away.", tamil: "வானமும் பூமியும் ஒழிந்துபோம், என் வார்த்தைகளோ ஒழிந்துபோவதில்லை.", ref: "மத்தேயு / Matthew 24:35" },
    { text: "And as you wish that others would do to you, do so to them.", tamil: "மனுஷர் உங்களுக்கு எப்படிச் செய்யவேண்டுமென்று விரும்புகிறீர்களோ, அப்படியே நீங்களும் அவர்களுக்குச் செய்யுங்கள்.", ref: "லூக்கா / Luke 6:31" },
    { text: "And you will know the truth, and the truth will set you free.", tamil: "சத்தியத்தையும் அறிவீர்கள், சத்தியம் உங்களை விடுதலையாக்கும்.", ref: "யோவான் / John 8:32" },
    { text: "Therefore welcome one another as Christ has welcomed you, for the glory of God.", tamil: "ஆதலால், தேவனோடு மகிமை உண்டாகும்படி, கிறிஸ்து நம்மை ஏற்றுக்கொண்டதுபோல, நீங்களும் ஒருவரையொருவர் ஏற்றுக்கொள்ளுங்கள்.", ref: "ரோமர் / Romans 15:7" },
    { text: "Therefore, my beloved brothers, be steadfast, immovable, always abounding in the work of the Lord...", tamil: "ஆகையால், எனக்குப் பிரியமான சகோதரரே... கர்த்தருடைய கிரியையிலே எப்பொழுதும் பெருகுகிறவர்களாயுமிருங்கள்.", ref: "கொரிந்தியர் 1 / 1 Corinthians 15:58" },
    { text: "For the things that are seen are transient, but the things that are unseen are eternal.", tamil: "காணப்படுகிறவைகள் அநித்தியமானவைகள், காணப்படாதவைகளோ நித்தியமானவைகள்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 4:18" },
    { text: "For freedom Christ has set us free; stand firm therefore, and do not submit again to a yoke of slavery.", tamil: "நீங்கள் மறுபடியும் அடிமைத்தனத்தின் நுகத்துக்குட்படாமல், கிறிஸ்து நமக்கு உண்டாக்கின சுயாதீன நிலைமையிலே நிலைகொண்டிருங்கள்.", ref: "கலாத்தியர் / Galatians 5:1" },
    { text: "And do not grieve the Holy Spirit of God, by whom you were sealed for the day of redemption.", tamil: "அன்றியும், நீங்கள் மீட்கப்படும் நாளுக்கென்று முத்திரையாகப் பெற்ற தேவனுடைய பரிசுத்த ஆவியை துக்கப்படுத்தாதிருங்கள்.", ref: "எபேசியர் / Ephesians 4:30" },
    { text: "I press on toward the goal for the prize of the upward call of God in Christ Jesus.", tamil: "கிறிஸ்து இயேசுவுக்குள் தேவன் அழைத்த பரம அழைப்பின் பந்தயப்பொருளுக்காக இலக்கை நோக்கித் தொடருகிறேன்.", ref: "பிலிப்பியர் / Philippians 3:14" },
    { text: "Bearing with one another and, if one has a complaint against another, forgiving each other...", tamil: "ஒருவரையொருவர் தாங்கி, ஒருவர்பேரில் ஒருவருக்குக் குறைபாடுண்டானால், கிறிஸ்து உங்களுக்கு மன்னித்ததுபோல, ஒருவருக்கொருவர் மன்னியுங்கள்.", ref: "கொலோசெயர் / Colossians 3:13" },
    { text: "Pray without ceasing.", tamil: "இடைவிடாமல் ஜெபம்பண்ணுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:17" },
    { text: "But the Lord is faithful. He will establish you and guard you against the evil one.", tamil: "கர்த்தரோ உண்மையுள்ளவர், அவர் உங்களை ஸ்திரப்படுத்தி, தீமையினின்று காத்துக்கொள்ளுவார்.", ref: "தெசலோனிக்கேயர் 2 / 2 Thessalonians 3:3" },
    { text: "But godliness with contentment is great gain.", tamil: "போதுமென்கிற மனதுடனேகூடிய தேவபக்தியே மிகுந்த ஆதாயம்.", ref: "தீமோத்தேயு 1 / 1 Timothy 6:6" },
    { text: "Do your best to present yourself to God as one approved, a worker who has no need to be ashamed...", tamil: "நீ வெட்கப்படத் தேவையில்லாத வேலையாளாயும், சத்திய வசனத்தை நிதானமாய்ப் பகுத்துப் போதிக்கிறவனாயும், உன்னைத் தேவனுக்கு முன்பாக உத்தமனாக நிறுத்தும்படி ஜாக்கிரதையாயிரு.", ref: "தீமோத்தேயு 2 / 2 Timothy 2:15" },
    { text: "For the word of God is living and active, sharper than any two-edged sword...", tamil: "தேவனுடைய வார்த்தையானது ஜீவனும் வல்லமையுமுள்ளதாயும், இருபுறமும் கருக்குள்ள எந்தப் பட்டயத்திலும் கருக்கானதாயும்...", ref: "எபிரெயர் / Hebrews 4:12" },
    { text: "Do not neglect to do good and to share what you have, for such sacrifices are pleasing to God.", tamil: "நன்மைசெய்யவும், தர்மஞ்செய்யவும் மறவாதிருங்கள்; இப்படிப்பட்ட பலிகளின்மேல் தேவன் பிரியமாயிருக்கிறார்.", ref: "எபிரெயர் / Hebrews 13:16" },
    { text: "Draw near to God, and he will draw near to you.", tamil: "தேவனிடத்தில் சேருங்கள், அப்பொழுது அவர் உங்களிடத்தில் சேருவார்.", ref: "யாக்கோபு / James 4:8" },
    { text: "Like newborn infants, long for the pure spiritual milk, that by it you may grow up into salvation.", tamil: "நீங்கள் இரட்சிப்பை அடையும்படி வளருகிறதற்காக, புதிதாய்ப் பிறந்த குழந்தைகளைப்போல, திருவசனமாகிய களங்கமில்லாத ஞானப்பாலின்மேல் வாஞ்சையாயிருங்கள்.", ref: "பேதுரு 1 / 1 Peter 2:2" },
    { text: "Little children, you are from God and have overcome them, for he who is in you is greater than he who is in the world.", tamil: "பிள்ளைகளே, நீங்கள் தேவனால் உண்டாயிருந்து, அவர்களை ஜெயித்தீர்கள்; ஏனெனில் உலகத்திலிருக்கிறவனிலும் உங்களிலிருக்கிறவர் பெரியவர்.", ref: "யோவான் 1 / 1 John 4:4" },
    { text: "And he who was seated on the throne said, 'Behold, I am making all things new.'", tamil: "சிங்காசனத்தின்மேல் வீற்றிருந்தவர்: இதோ, நான் சகலத்தையும் புதிதாக்குகிறேன் என்றார்.", ref: "வெளிப்படுத்தின விசேஷம் / Revelation 21:5" },
    { text: "Wait for the Lord; be strong, and let your heart take courage; wait for the Lord!", tamil: "கர்த்தருக்குக் காத்திரு, அவர் உன் இருதயத்தை ஸ்திரப்படுத்துவார்; திடமனதாயிருந்து, கர்த்தருக்கே காத்திரு.", ref: "சங்கீதம் / Psalm 27:14" },
    { text: "The steps of a man are established by the Lord, when he delights in his way.", tamil: "நல்ல மனுஷனுடைய நடைகள் கர்த்தரால் உறுதிப்படும், அவனுடைய வழியின்மேல் அவர் பிரியமாயிருக்கிறார்.", ref: "சங்கீதம் / Psalm 37:23" },
    { text: "Restore to me the joy of your salvation, and uphold me with a willing spirit.", tamil: "உமது இரட்சணியத்தின் சந்தோஷத்தை திரும்பவும் எனக்குத் தந்து, உற்சாகமான ஆவி என்னைத் தாங்கும்படி செய்யும்.", ref: "சங்கீதம் / Psalm 51:12" },
    { text: "The reward for humility and fear of the Lord is riches and honor and life.", tamil: "தாழ்மைக்கும் கர்த்தருக்குப் பயப்படுதலுக்கும் வரும் பலன் ஐசுவரியமும் மகிமையும் ஜீவனுமாம்.", ref: "நீதிமொழிகள் / Proverbs 22:4" },
    { text: "The Lord is good to those who wait for him, to the soul who seeks him.", tamil: "தமக்குக் காத்திருக்கிறவர்களுக்கும், தம்மைத் தேடுகிற ஆத்துமாவுக்கும் கர்த்தர் நல்லவர்.", ref: "புலம்பல் / Lamentations 3:25" },
    { text: "The Lord is good, a stronghold in the day of trouble; he knows those who take refuge in him.", tamil: "கர்த்தர் நல்லவர், இக்கட்டு நாளிலே அரணான கோட்டை; தம்மை நம்புகிறவர்களை அறிந்திருக்கிறார்.", ref: "நாகூம் / Nahum 1:7" },
        // --- MONTH 11 (Days 302-331) ---
    { text: "Know that the Lord, he is God! It is he who made us, and we are his; we are his people, and the sheep of his pasture.", tamil: "கர்த்தரே தேவனென்று அறியுங்கள்; நாம் அல்ல, அவரே நம்மை உண்டாக்கினார்; நாம் அவர் ஜனங்களும், அவர் மேய்ச்சலின் ஆடுகளுமாயிருக்கிறோம்.", ref: "சங்கீதம் / Psalm 100:3" },
    { text: "Open my eyes, that I may behold wondrous things out of your law.", tamil: "உமது வேதத்திலுள்ள அதிசயங்களை நான் பார்க்கும்படிக்கு, என் கண்களைத் திறந்தருளும்.", ref: "சங்கீதம் / Psalm 119:18" },
    { text: "As in water face reflects face, so the heart of man reflects the man.", tamil: "தண்ணீரில் முகத்துக்கு முகம் ஒத்திருக்குமாப்போல, மனுஷரில் இருதயத்திற்கு இருதயம் ஒத்திருக்கும்.", ref: "நீதிமொழிகள் / Proverbs 27:19" },
    { text: "For my thoughts are not your thoughts, neither are your ways my ways, declares the Lord.", tamil: "என் நினைவுகள் உங்கள் நினைவுகள் அல்ல; உங்கள் வழிகள் என் வழிகளும் அல்லவென்று கர்த்தர் சொல்லுகிறார்.", ref: "ஏசாயா / Isaiah 55:8" },
    { text: "You will seek me and find me, when you seek me with all your heart.", tamil: "உங்கள் முழு இருதயத்தோடும் என்னைத் தேடும்போது, என்னைத் தேடிக் கண்டுபிடிப்பீர்கள்.", ref: "எரேமியா / Jeremiah 29:13" },
    { text: "Blessed are those who mourn, for they shall be comforted.", tamil: "துயரப்படுகிறவர்கள் பாக்கியவான்கள்; அவர்கள் ஆறுதலடைவார்கள்.", ref: "மத்தேயு / Matthew 5:4" },
    { text: "Blessed are those who hunger and thirst for righteousness, for they shall be satisfied.", tamil: "நீதியின்மேல் பசியும் தாகமுமுள்ளவர்கள் பாக்கியவான்கள்; அவர்கள் திருப்தியடைவார்கள்.", ref: "மத்தேயு / Matthew 5:6" },
    { text: "For if you forgive others their trespasses, your heavenly Father will also forgive you.", tamil: "மனுஷருடைய தப்பிதங்களை நீங்கள் அவர்களுக்கு மன்னித்தால், உங்கள் பரம பிதா உங்களுக்கும் மன்னிப்பார்.", ref: "மத்தேயு / Matthew 6:14" },
    { text: "And behold, I am with you always, to the end of the age.", tamil: "இதோ, உலகத்தின் முடிவுபரியந்தம் சகல நாட்களிலும் நான் உங்களுடனேகூட இருக்கிறேன்.", ref: "மத்தேயு / Matthew 28:20" },
    { text: "For what does it profit a man to gain the whole world and forfeit his soul?", tamil: "மனுஷன் உலகம் முழுவதையும் ஆதாயப்படுத்திக்கொண்டாலும், தன் ஜீவனை நஷ்டப்படுத்தினால் அவனுக்கு லாபமென்ன?", ref: "மாற்கு / Mark 8:36" },
    { text: "Fear not, little flock, for it is your Father's good pleasure to give you the kingdom.", tamil: "பயப்படாதே சிறுமந்தையே, உங்களுக்கு ராஜ்யத்தைக் கொடுக்க உங்கள் பிதா பிரியமாயிருக்கிறார்.", ref: "லூக்கா / Luke 12:32" },
    { text: "God is spirit, and those who worship him must worship in spirit and truth.", tamil: "தேவன் ஆவியாயிருக்கிறார், அவரைத் தொழுதுகொள்ளுகிறவர்கள் ஆவியோடும் உண்மையோடும் அவரைத் தொழுதுகொள்ளவேண்டும்.", ref: "யோவான் / John 4:24" },
    { text: "Jesus said to them, 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst.'", tamil: "இயேசு அவர்களை நோக்கி: ஜீவ அப்பம் நானே, என்னிடத்தில் வருகிறவன் ஒருக்காலும் பசியடையான், என்னிடத்தில் விசுவாசமாயிருக்கிறவன் ஒருக்காலும் தாகமடையான்.", ref: "யோவான் / John 6:35" },
    { text: "A new commandment I give to you, that you love one another: just as I have loved you, you also are to love one another.", tamil: "நீங்கள் ஒருவரிலொருவர் அன்பாயிருங்கள்; நான் உங்களில் அன்பாயிருந்ததுபோல நீங்களும் ஒருவரிலொருவர் அன்பாயிருங்கள் என்கிற புதிய கட்டளையை உங்களுக்குக் கொடுக்கிறேன்.", ref: "யோவான் / John 13:34" },
    { text: "I have said these things to you, that in me you may have peace. In the world you will have tribulation. But take heart; I have overcome the world.", tamil: "என்னிடத்தில் உங்களுக்குச் சமாதானம் உண்டாயிருக்கும்பொருட்டு இவைகளை உங்களுக்குச் சொன்னேன். உலகத்தில் உங்களுக்கு உபத்திரவம் உண்டு, ஆனாலும் திடன்கொள்ளுங்கள்; நான் உலகத்தை ஜெயித்தேன் என்றார்.", ref: "யோவான் / John 16:33" },
    { text: "And there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved.", tamil: "அவராலேயன்றி வேறொருவராலும் இரட்சிப்பு இல்லை; நாம் இரட்சிக்கப்படும்படிக்கு வானத்தின் கீழே, மனுஷர்களுக்குள்ளே, அவருடைய நாமமேயல்லாமல் வேறொரு நாமம் கட்டளையிடப்படவும் இல்லை.", ref: "அப்போஸ்தலர் / Acts 4:12" },
    { text: "For by the grace given to me I say to everyone among you not to think of himself more highly than he ought to think...", tamil: "அல்லாமலும், எனக்கு அருளப்பட்ட கிருபையினாலே நான் சொல்லுகிறதாவது: உங்களில் எவனானாலும் தன்னைக்குறித்து எண்ணவேண்டியதற்கு மிஞ்சி எண்ணாமல்...", ref: "ரோமர் / Romans 12:3" },
    { text: "For whatever was written in former days was written for our instruction, that through endurance and through the encouragement of the Scriptures we might have hope.", tamil: "தேவவசனத்தினால் உண்டாகும் பொறுமையினாலும் ஆறுதலினாலும் நாம் நம்பிக்கையுள்ளவர்களாகும்படிக்கு, முன்பு எழுதியிருக்கிறவைகளெல்லாம் நமக்குப் போதனையாக எழுதியிருக்கிறது.", ref: "ரோமர் / Romans 15:4" },
    { text: "But, as it is written, 'What no eye has seen, nor ear heard, nor the heart of man imagined, what God has prepared for those who love him.'", tamil: "எழுதியிருக்கிறபடி: தேவன் தம்மில் அன்புகூருகிறவர்களுக்கு ஆயத்தம்பண்ணினவைகளைக் கண்ணுங்காணவில்லை, காதுங்கேட்கவில்லை, அவைகள் மனுஷனுடைய இருதயத்தில் தோன்றவுமில்லை.", ref: "கொரிந்தியர் 1 / 1 Corinthians 2:9" },
    { text: "For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God.", tamil: "நாம் அவருக்குள் தேவனுடைய நீதியாகும்படிக்கு, பாவம் அறியாத அவரை நமக்காகப் பாவமாக்கினார்.", ref: "கொரிந்தியர் 2 / 2 Corinthians 5:21" },
    { text: "But I say, walk by the Spirit, and you will not gratify the desires of the flesh.", tamil: "பின்னும் நான் சொல்லுகிறதென்னவென்றால், ஆவிக்கேற்றபடி நடந்துகொள்ளுங்கள், அப்பொழுது மாம்ச இச்சையை நிறைவேற்றமாட்டீர்கள்.", ref: "கலாத்தியர் / Galatians 5:16" },
    { text: "For at one time you were darkness, but now you are light in the Lord. Walk as children of light.", tamil: "முற்காலத்தில் நீங்கள் அந்தகாரமாயிருந்தீர்கள், இப்பொழுதோ கர்த்தருக்குள் வெளிச்சமாயிருக்கிறீர்கள்; வெளிச்சத்தின் பிள்ளைகளாய் நடந்துகொள்ளுங்கள்.", ref: "எபேசியர் / Ephesians 5:8" },
    { text: "Have this mind among yourselves, which is yours in Christ Jesus.", tamil: "கிறிஸ்து இயேசுவிலிருந்த சிந்தையே உங்களிலும் இருக்கக்கடவது.", ref: "பிலிப்பியர் / Philippians 2:5" },
    { text: "But our citizenship is in heaven, and from it we await a Savior, the Lord Jesus Christ.", tamil: "நம்முடைய குடியிருப்போ பரலோகத்திலிருக்கிறது, அங்கேயிருந்து கர்த்தராகிய இயேசுகிறிஸ்து என்னும் இரட்சகர் வர எதிர்பார்த்துக்கொண்டிருக்கிறோம்.", ref: "பிலிப்பியர் / Philippians 3:20" },
    { text: "Therefore, as you received Christ Jesus the Lord, so walk in him.", tamil: "ஆகையால், நீங்கள் கர்த்தராகிய இயேசுகிறிஸ்துவை ஏற்றுக்கொண்டபடியே, அவருக்குள் வேர்கொண்டவர்களும்...", ref: "கொலோசெயர் / Colossians 2:6" },
    { text: "But test everything; hold fast what is good.", tamil: "எல்லாவற்றையும் சோதித்துப்பார்த்து, நலமானதைப் பிடித்துக்கொள்ளுங்கள்.", ref: "தெசலோனிக்கேயர் 1 / 1 Thessalonians 5:21" },
    { text: "And let us consider how to stir up one another to love and good works.", tamil: "அன்புகூரவும் நற்கிரியைகளைச் செய்யவும் நாம் ஏவப்படும்படி ஒருவரையொருவர் கவனித்து;", ref: "எபிரெயர் / Hebrews 10:24" },
    { text: "Strive for peace with everyone, and for the holiness without which no one will see the Lord.", tamil: "யாவரோடும் சமாதானமாயிருக்கவும், பரிசுத்தமுள்ளவர்களாயிருக்கவும் நாடுங்கள்; பரிசுத்தமில்லாமல் ஒருவனும் கர்த்தரைத் தரிசிப்பதில்லையே.", ref: "எபிரெயர் / Hebrews 12:14" },
    { text: "In this is love, not that we have loved God but that he loved us and sent his Son to be the propitiation for our sins.", tamil: "நாம் தேவனிடத்தில் அன்புகூர்ந்ததினால் அல்ல, அவர் நம்மிடத்தில் அன்புகூர்ந்து, நம்முடைய பாவங்களை நிவிர்த்திசெய்கிற கிருபாதாரபலியாகத் தம்முடைய குமாரனை அனுப்பினதினாலே அன்பு உண்டாயிருக்கிறது.", ref: "யோவான் 1 / 1 John 4:10" },
    { text: "Now to him who is able to keep you from stumbling and to present you blameless before the presence of his glory with great joy.", tamil: "வழுவாதபடி உங்களைக் காக்கவும், தமது மகிமையுள்ள சந்நிதானத்திலே மாசற்றவர்களாய் உங்களை மிகுந்த மகிழ்ச்சியோடே நிறுத்தவும் வல்லமையுள்ளவரும்...", ref: "யூதா / Jude 1:24" },
        // --- MONTH 12 (Days 332-365) - THE GRAND FINALE ---
    { text: "For I know that my Redeemer lives, and at the last he will stand upon the earth.", tamil: "என் மீட்பர் உயிரோடிருக்கிறார் என்றும், அவர் கடைசிநாளில் பூமியின்மேல் நிற்பார் என்றும் நான் அறிந்திருக்கிறேன்.", ref: "யோபு / Job 19:25" },
    { text: "Your steadfast love, O Lord, extends to the heavens, your faithfulness to the clouds.", tamil: "கர்த்தாவே, உமது கிருபை வானங்களிலுள்ளது; உமது சத்தியம் மேகங்கள்மட்டும் எட்டும்.", ref: "சங்கீதம் / Psalm 36:5" },
    { text: "Create in me a clean heart, O God, and renew a right spirit within me.", tamil: "தேவனே, சுத்த இருதயத்தை என்னிலே சிருஷ்டியும், நிலைவரமான ஆவியை என் உள்ளத்திலே புதுப்பியும்.", ref: "சங்கீதம் / Psalm 51:10" },
    { text: "From the end of the earth I call to you when my heart is faint. Lead me to the rock that is higher than I.", tamil: "என் இருதயம் தொய்யும்போது, பூமியின் கடையாந்தரத்திலிருந்து உம்மை நோக்கிக் கூப்பிடுவேன்; எனக்கு எட்டாத உயரமான கன்மலையில் என்னைக் கொண்டுபோய்விடும்.", ref: "சங்கீதம் / Psalm 61:2" },
    { text: "Bless the Lord, O my soul, and all that is within me, bless his holy name!", tamil: "என் ஆத்துமாவே, கர்த்தரை ஸ்தோத்திரி; என் முழு உள்ளமே, அவருடைய பரிசுத்த நாமத்தை ஸ்தோத்திரி.", ref: "சங்கீதம் / Psalm 103:1" },
    { text: "Thy word is a lamp unto my feet, and a light unto my path.", tamil: "உம்முடைய வசனம் என் கால்களுக்குத் தீபமும், என் பாதைக்கு வெளிச்சமுமாயிருக்கிறது.", ref: "சங்கீதம் / Psalm 119:105" },
    { text: "Let everything that has breath praise the Lord! Praise the Lord!", tamil: "சுவாசமுள்ள யாவும் கர்த்தரைத் துதிப்பதாக. அல்லேலூயா.", ref: "சங்கீதம் / Psalm 150:6" },
    { text: "Trust in the Lord with all your heart, and do not lean on your own understanding.", tamil: "உன் சுயபுத்தியின்மேல் சாயாமல், உன் முழு இருதயத்தோடும் கர்த்தரில் நம்பிக்கையாயிருந்து...", ref: "நீதிமொழிகள் / Proverbs 3:5" },
    { text: "The steadfast love of the Lord never ceases; his mercies never come to an end.", tamil: "கர்த்தருடைய கிருபைகளே, நாம் நிர்மூலமாகாதிருக்கிறது; அவருடைய இரக்கங்களுக்கு முடிவில்லை.", ref: "புலம்பல் / Lamentations 3:22" },
    { text: "They are new every morning; great is your faithfulness.", tamil: "அவைகள் காலைதோறும் புதியவைகள்; உமது உண்மை பெரிதாயிருக்கிறது.", ref: "புலம்பல் / Lamentations 3:23" },
    { text: "For I the Lord do not change; therefore you, O children of Jacob, are not consumed.", tamil: "நான் கர்த்தர், நான் மாறாதவர்; ஆகையால் யாக்கோபின் புத்திரராகிய நீங்கள் நிர்மூலமாகவில்லை.", ref: "மல்கியா / Malachi 3:6" },
    { text: "Jesus Christ is the same yesterday and today and forever.", tamil: "இயேசுகிறிஸ்து நேற்றும் இன்றும் என்றென்றைக்கும் மாறாதவராயிருக்கிறார்.", ref: "எபிரெயர் / Hebrews 13:8" },
    { text: "And he said to them, 'Go into all the world and proclaim the gospel to the whole creation.'", tamil: "பின்பு, அவர் அவர்களை நோக்கி: நீங்கள் உலகமெங்கும்போய், சர்வ சிருஷ்டிக்கும் சுவிசேஷத்தைப் பிரசங்கியுங்கள்.", ref: "மாற்கு / Mark 16:15" },
    { text: "For with God nothing will be impossible.", tamil: "தேவனால் கூடாத காரியம் ஒன்றுமில்லை என்றான்.", ref: "லூக்கா / Luke 1:37" },
    { text: "Jesus answered him, 'Truly, truly, I say to you, unless one is born again he cannot see the kingdom of God.'", tamil: "இயேசு அவனுக்குப் பிரதியுத்தரமாக: ஒருவன் மறுபடியும் பிறவாவிட்டால் தேவனுடைய ராஜ்யத்தைக் காணமாட்டான் என்று மெய்யாகவே மெய்யாகவே உனக்குச் சொல்லுகிறேன் என்றார்.", ref: "யோவான் / John 3:3" },
    { text: "I am the good shepherd. The good shepherd lays down his life for the sheep.", tamil: "நானே நல்ல மேய்ப்பன்: நல்ல மேய்ப்பன் ஆடுகளுக்காகத் தன் ஜீவனைக் கொடுக்கிறான்.", ref: "யோவான் / John 10:11" },
    { text: "If you love me, you will keep my commandments.", tamil: "நீங்கள் என்னிடத்தில் அன்பாயிருந்தால் என் கற்பனைகளைக் கைக்கொள்ளுங்கள்.", ref: "யோவான் / John 14:15" },
    { text: "Abide in me, and I in you. As the branch cannot bear fruit by itself, unless it abides in the vine, neither can you, unless you abide in me.", tamil: "என்னில் நிலைத்திருங்கள், நானும் உங்களில் நிலைத்திருப்பேன்; கொடியானது திராட்சச்செடியில் நிலைத்திராவிட்டால் அது தானாய்க் கனிகொடுக்கமாட்டாததுபோல, நீங்களும் என்னில் நிலைத்திராவிட்டால், கனிகொடுக்கமாட்டீர்கள்.", ref: "யோவான் / John 15:4" },
    { text: "Greater love has no one than this, that someone lay down his life for his friends.", tamil: "ஒருவன் தன் சிநேகிதருக்காகத் தன் ஜீவனைக் கொடுக்கிற அன்பிலும் சிறந்த அன்பு வேறொருவரிடத்திலுமில்லை.", ref: "யோவான் / John 15:13" },
    { text: "Sanctify them in the truth; your word is truth.", tamil: "உம்முடைய சத்தியத்தினாலே அவர்களைப் பரிசுத்தமாக்கும்; உம்முடைய வசனமே சத்தியம்.", ref: "யோவான் / John 17:17" },
    { text: "But you will receive power when the Holy Spirit has come upon you, and you will be my witnesses...", tamil: "பரிசுத்த ஆவி உங்களிடத்தில் வரும்போது நீங்கள் பெலனடைந்து... எனக்குச் சாட்சிகளாயிருப்பீர்கள் என்றார்.", ref: "அப்போஸ்தலர் / Acts 1:8" },
    { text: "And we know that for those who love God all things work together for good, for those who are called according to his purpose.", tamil: "அன்றியும், அவருடைய தீர்மானத்தின்படி அழைக்கப்பட்டவர்களாய் தேவனிடத்தில் அன்புகூருகிறவர்களுக்குச் சகலமும் நன்மைக்கேதுவாக நடக்கிறது என்று அறிந்திருக்கிறோம்.", ref: "ரோமர் / Romans 8:28" },
    { text: "If God is for us, who can be against us?", tamil: "தேவன் நம்முடைய பட்சத்திலிருந்தால் நமக்கு விரோதமாயிருப்பவன் யார்?", ref: "ரோமர் / Romans 8:31" },
    { text: "Do you not know that you are God's temple and that God's Spirit dwells in you?", tamil: "நீங்கள் தேவனுடைய ஆலயமாயிருக்கிறீர்களென்றும், தேவனுடைய ஆவி உங்களில் வாசமாயிருக்கிறாரென்றும் அறியாதிருக்கிறீர்களா?", ref: "கொரிந்தியர் 1 / 1 Corinthians 3:16" },
    { text: "Therefore, if anyone is in Christ, he is a new creation. The old has passed away; behold, the new has come.", tamil: "இப்படியிருக்க, ஒருவன் கிறிஸ்துவுக்குள்ளிருந்தால் புதுச்சிருஷ்டியாயிருக்கிறான்; பழையவைகள் ஒழிந்துபோயின, எல்லாம் புதிதாயின.", ref: "கொரிந்தியர் 2 / 2 Corinthians 5:17" },
    { text: "For by grace you have been saved through faith. And this is not your own doing; it is the gift of God.", tamil: "கிருபையினாலே விசுவாசத்தைக்கொண்டு இரட்சிக்கப்பட்டீர்கள்; இது உங்களால் உண்டானதல்ல, இது தேவனுடைய ஈவு.", ref: "எபேசியர் / Ephesians 2:8" },
    { text: "I can do all things through him who strengthens me.", tamil: "என்னைப் பெலப்படுத்துகிற கிறிஸ்துவினாலே எல்லாவற்றையும் செய்ய எனக்குப் பெலனுண்டு.", ref: "பிலிப்பியர் / Philippians 4:13" },
    { text: "He is the image of the invisible God, the firstborn of all creation.", tamil: "அவர் அதரிசனமான தேவனுடைய தற்சுரூபமும், சர்வ சிருஷ்டிக்கும் முந்தினபேறுமானவர்.", ref: "கொலோசெயர் / Colossians 1:15" },
    { text: "For in him the whole fullness of deity dwells bodily.", tamil: "ஏனெனில், தேவத்துவத்தின் பரிபூரணமெல்லாம் சரீரப்பிரகாரமாக அவருக்குள் வாசமாயிருக்கிறது.", ref: "கொலோசெயர் / Colossians 2:9" },
    { text: "For there is one God, and there is one mediator between God and men, the man Christ Jesus.", tamil: "தேவன் ஒருவரே, தேவனுக்கும் மனுஷருக்கும் மத்தியஸ்தரும் ஒருவரே.", ref: "தீமோத்தேயு 1 / 1 Timothy 2:5" },
    { text: "Now faith is the assurance of things hoped for, the conviction of things not seen.", tamil: "விசுவாசமானது நம்பப்படுகிறவைகளின் உறுதியும், காணப்படாதவைகளின் நிச்சயமுமாயிருக்கிறது.", ref: "எபிரெயர் / Hebrews 11:1" },
    { text: "Therefore confess your sins to each other and pray for each other so that you may be healed.", tamil: "நீங்கள் சொஸ்தமடையும்படிக்கு, உங்கள் குற்றங்களை ஒருவருக்கொருவர் அறிக்கையிட்டு, ஒருவருக்காக ஒருவர் ஜெபம்பண்ணுங்கள்.", ref: "யாக்கோபு / James 5:16" },
    { text: "If we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.", tamil: "நம்முடைய பாவங்களை நாம் அறிக்கையிட்டால், பாவங்களை நமக்கு மன்னித்து எவ்வித அநியாயமு நீங்க நம்மைச் சுத்திகரிப்பதற்கு அவர் உண்மையு நீதியுமுள்ளவராயிருக்கிறார்.", ref: "யோவான் 1 / 1 John 1:9" },
    { text: "The grace of the Lord Jesus be with all. Amen.", tamil: "நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவினுடைய கிருபை உங்களனைவரோடுங்கூட இருப்பதாக. ஆமென்.", ref: "வெளிப்படுத்தின விசேஷம் / Revelation 22:21" }

];

// Helper to let app.js easily grab the date-matched verse without page clashing
function getCalculatedDailyVerseObject() {
    const today = new Date();
    const dateKey = (today.getFullYear() * 10000) + ((today.getMonth() + 1) * 100) + today.getDate();
    const verseIndex = dateKey % BIBLE_VERSES_VAULT.length;
    return BIBLE_VERSES_VAULT[verseIndex];
}
